import * as React from 'react'
import {
  type ColumnDef,
  type SortingState,
  flexRender,
  getCoreRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
} from '@tanstack/react-table'

import { cn } from '../../lib/utils'
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from './table'

interface DataTableProps<TData> {
  columns: ColumnDef<TData, unknown>[]
  data: TData[]
  emptyMessage?: string
  className?: string
  pageSizeOptions?: number[]
  initialPageSize?: number
}

export function DataTable<TData>({
  columns,
  data,
  emptyMessage = 'No rows to display.',
  className,
  pageSizeOptions = [20, 50, 100],
  initialPageSize = 20,
}: DataTableProps<TData>) {
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [pagination, setPagination] = React.useState({
    pageIndex: 0,
    pageSize: initialPageSize,
  })

  const table = useReactTable({
    data,
    columns,
    state: {
      sorting,
      pagination,
    },
    onSortingChange: setSorting,
    onPaginationChange: setPagination,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
  })

  return (
    <div className={cn('space-y-3', className)}>
      <div className="rounded-md border border-[var(--border)] bg-[var(--card-bg)]">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => {
                  const canSort = header.column.getCanSort()
                  const sortState = header.column.getIsSorted()

                  return (
                    <TableHead key={header.id}>
                      {header.isPlaceholder ? null : canSort ? (
                        <button
                          type="button"
                          className="inline-flex items-center gap-1 text-left text-xs font-semibold uppercase tracking-wide text-[var(--muted)]"
                          onClick={header.column.getToggleSortingHandler()}
                        >
                          {flexRender(header.column.columnDef.header, header.getContext())}
                          <span aria-hidden="true">
                            {sortState === 'asc' ? '↑' : sortState === 'desc' ? '↓' : '↕'}
                          </span>
                        </button>
                      ) : (
                        <span className="text-xs font-semibold uppercase tracking-wide text-[var(--muted)]">
                          {flexRender(header.column.columnDef.header, header.getContext())}
                        </span>
                      )}
                    </TableHead>
                  )
                })}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow key={row.id}>
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id}>
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-20 text-center text-[var(--muted)]">
                  {emptyMessage}
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>

      <div className="flex flex-wrap items-center justify-between gap-2">
        <div className="text-xs text-[var(--muted)]">
          Page {table.getState().pagination.pageIndex + 1} of {Math.max(table.getPageCount(), 1)}
        </div>
        <div className="flex items-center gap-2">
          <select
            className="role-select"
            value={table.getState().pagination.pageSize}
            onChange={(event) => table.setPageSize(Number(event.target.value))}
          >
            {pageSizeOptions.map((size) => (
              <option key={size} value={size}>
                {size} / page
              </option>
            ))}
          </select>
          <button
            type="button"
            className="k-button k-button-md k-rounded-md"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            Previous
          </button>
          <button
            type="button"
            className="k-button k-button-md k-rounded-md"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            Next
          </button>
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState, type ReactElement } from 'react'
import { Button } from '@progress/kendo-react-buttons'
import { Card, CardBody, CardHeader, CardTitle } from '@progress/kendo-react-layout'
import { useNavigate, useParams } from 'react-router-dom'
import { RoleGuard, moduleRoleMap } from '../components/RoleGuard'
import { useAuthStore } from '../store/authStore'
import { useDisplayCurrency } from '../store/currencyStore'
import { roleDashboardPath, roleLabels } from '../types/auth'
import { dashboardService, type MetricDto } from '../services/dashboardService'
import { AccountantOperationsModule } from './modules/AccountantOperationsModule'
import { APInvoicesModule } from './modules/APInvoicesModule'
import { ARInvoicesModule } from './modules/ARInvoicesModule'
import { AdminReportsModule } from './modules/AdminReportsModule'
import { AuditorModulesModule, type AuditorModuleKey } from './modules/AuditorModulesModule'
import { AuthorizedViewerModule, type AvModuleKey } from './modules/AuthorizedViewerModule'
import { BankDirectoryModule } from './modules/BankDirectoryModule'
import { EmployeeWorkspaceModule } from './modules/EmployeeWorkspaceModule'
import { ExtendedRoleOperationsModule } from './modules/ExtendedRoleOperationsModule'
import { FacultyAdminModule, type FacultyAdminModuleKey } from './modules/FacultyAdminModule'
import { FinancialReportsModule } from './modules/FinancialReportsModule'
import { FiscalPeriodsModule } from './modules/FiscalPeriodsModule'
import { IntegrationSettingsModule } from './modules/IntegrationSettingsModule'
import { JobQueueModule } from './modules/JobQueueModule'
import { PayrollOperationsModule } from './modules/PayrollOperationsModule'
import { RolesPermissionsModule } from './modules/RolesPermissionsModule'
import { SecurityPolicyModule } from './modules/SecurityPolicyModule'
import { SystemHealthModule } from './modules/SystemHealthModule'
import { SystemSettingsModule } from './modules/SystemSettingsModule'
import { UserManagementModule } from './modules/UserManagementModule'

const labelize = (value: string) =>
  value
    .split('-')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ')

const SIMPLE_MODULE_MAP: Partial<Record<string, () => ReactElement>> = {
  'user-management': () => <UserManagementModule />,
  'roles-permissions': () => <RolesPermissionsModule />,
  'job-queue': () => <JobQueueModule />,
  'fiscal-periods': () => <FiscalPeriodsModule />,
  'integration-settings': () => <IntegrationSettingsModule />,
  'security-policy': () => <SecurityPolicyModule />,
  'system-health': () => <SystemHealthModule />,
  'admin-reports': () => <AdminReportsModule />,
  'system-settings': () => <SystemSettingsModule />,
  'bank-directory': () => <BankDirectoryModule />,
  'accounts-payable': () => <APInvoicesModule />,
  'accounts-receivable': () => <ARInvoicesModule />,
}

function renderSpecialModule(moduleKey: string): ReactElement | null {
  const simpleRender = SIMPLE_MODULE_MAP[moduleKey]
  if (simpleRender) {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}>{simpleRender()}</RoleGuard>
  }

  if (moduleKey === 'general-ledger' || moduleKey === 'bank-reconciliation') {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><AccountantOperationsModule moduleKey={moduleKey} /></RoleGuard>
  }

  if (moduleKey === 'payroll') {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><PayrollOperationsModule /></RoleGuard>
  }

  if (moduleKey === 'financial-reports' || moduleKey === 'reports') {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><FinancialReportsModule /></RoleGuard>
  }

  if (moduleKey === 'expense-claims' || moduleKey === 'payslips' || moduleKey === 'profile') {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><EmployeeWorkspaceModule moduleKey={moduleKey} /></RoleGuard>
  }

  if (moduleKey === 'executive-summary' || moduleKey === 'av-reports') {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><AuthorizedViewerModule moduleKey={moduleKey as AvModuleKey} /></RoleGuard>
  }

  if (
    moduleKey === 'sod-report' || moduleKey === 'user-activity-timeline'
    || moduleKey === 'general-ledger-inquiry' || moduleKey === 'trial-balance'
    || moduleKey === 'vendor-master' || moduleKey === 'customer-master'
    || moduleKey === 'balance-sheet' || moduleKey === 'income-statement'
    || moduleKey === 'ap-aging' || moduleKey === 'ar-aging' || moduleKey === 'evidence-archive'
  ) {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><AuditorModulesModule moduleKey={moduleKey as AuditorModuleKey} /></RoleGuard>
  }

  if (moduleKey === 'dept-reports' || moduleKey === 'fa-approvals' || moduleKey === 'fa-reports') {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><FacultyAdminModule moduleKey={moduleKey as FacultyAdminModuleKey} /></RoleGuard>
  }

  if (
    moduleKey === 'department-report' || moduleKey === 'approvals'
    || moduleKey === 'audit-logs' || moduleKey === 'approvals-inbox' || moduleKey === 'budget-control'
  ) {
    return <RoleGuard allowedRoles={moduleRoleMap[moduleKey]}><ExtendedRoleOperationsModule moduleKey={moduleKey} /></RoleGuard>
  }

  return null
}

export const ModulePlaceholderPage = () => {
  useDisplayCurrency()

  const navigate = useNavigate()
  const { moduleKey } = useParams<{ moduleKey: string }>()
  const selectedRole = useAuthStore((state) => state.selectedRole)
  const user = useAuthStore((state) => state.user)
  const activeRole = selectedRole ?? user?.role ?? null
  const [metrics, setMetrics] = useState<MetricDto[]>([])
  const [loadingMetrics, setLoadingMetrics] = useState(false)
  const [metricsError, setMetricsError] = useState('')

  useEffect(() => {
    if (!activeRole) {
      setMetrics([])
      setMetricsError('')
      return
    }

    let isMounted = true
    setLoadingMetrics(true)
    setMetricsError('')

    void dashboardService
      .getMetrics(activeRole)
      .then((result) => {
        if (!isMounted) return
        setMetrics(result.metrics ?? [])
      })
      .catch(() => {
        if (!isMounted) return
        setMetrics([])
        setMetricsError('Unable to load live metrics for this module right now.')
      })
      .finally(() => {
        if (!isMounted) return
        setLoadingMetrics(false)
      })

    return () => {
      isMounted = false
    }
  }, [activeRole])

  if (moduleKey) {
    const special = renderSpecialModule(moduleKey)
    if (special) return special
  }

  const readableLabel = moduleKey ? labelize(moduleKey) : 'Module'
  const allowedRoles = moduleKey ? moduleRoleMap[moduleKey] : undefined

  if (!moduleKey || !allowedRoles) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{readableLabel}</CardTitle>
        </CardHeader>
        <CardBody>
          <p>This module is not recognized in the current CMNetwork configuration.</p>
          <Button themeColor="primary" onClick={() => navigate('/')}>Return Home</Button>
        </CardBody>
      </Card>
    )
  }

  const canView = !activeRole || allowedRoles.includes(activeRole)
  if (!canView) {
    const allowedRoleLabels = allowedRoles.map((role) => roleLabels[role]).join(', ')

    return (
      <Card>
        <CardHeader>
          <CardTitle>{readableLabel}</CardTitle>
        </CardHeader>
        <CardBody>
          <p>
            This module is available to {allowedRoleLabels}. Switch to one of those roles to continue.
          </p>
          <div className="quick-actions">
            <Button themeColor="primary" onClick={() => navigate(roleDashboardPath(allowedRoles[0]))}>
              Go to Dashboard
            </Button>
            <Button onClick={() => navigate('/')}>Return Home</Button>
          </div>
        </CardBody>
      </Card>
    )
  }

  return (
    <section className="page-fade-in">
      <div
        style={{
          border: '1px solid var(--border)',
          borderRadius: 'var(--radius-md)',
          background: 'var(--surface)',
          padding: '1.25rem',
          marginBottom: '1rem',
          boxShadow: 'var(--shadow)',
        }}
      >
        <p style={{ margin: '0 0 0.35rem', color: 'var(--muted)', fontSize: '0.82rem' }}>
          {activeRole ? `${roleLabels[activeRole]} workspace` : 'Module workspace'}
        </p>
        <h1 className="page-title" style={{ marginBottom: '0.5rem' }}>{readableLabel}</h1>
        <p style={{ margin: 0, color: 'var(--text)', maxWidth: '72ch' }}>
          This route is configured for live backend data only. Static placeholder module cards are removed.
        </p>
      </div>

      <Card className="dashboard-card">
        <CardHeader>
          <CardTitle>Live Data View</CardTitle>
        </CardHeader>
        <CardBody>
          {loadingMetrics && (
            <p className="card-subtitle" style={{ margin: 0 }}>Loading live metrics...</p>
          )}

          {!loadingMetrics && metricsError && (
            <p className="card-subtitle" style={{ margin: 0 }}>{metricsError}</p>
          )}

          {!loadingMetrics && !metricsError && metrics.length === 0 && (
            <p className="card-subtitle" style={{ margin: 0 }}>
              No live metrics are available for this role and module yet.
            </p>
          )}

          {!loadingMetrics && !metricsError && metrics.length > 0 && (
            <div className="dashboard-grid cols-3" style={{ marginTop: '0.25rem' }}>
              {metrics.slice(0, 6).map((metric) => (
                <div key={`${metric.title}-${metric.value}`} style={{ border: '1px solid var(--border)', borderRadius: '8px', padding: '0.75rem' }}>
                  <p style={{ margin: '0 0 0.25rem', color: 'var(--muted)', fontSize: '0.8rem' }}>{metric.title}</p>
                  <div style={{ fontWeight: 700, fontSize: '1.1rem' }}>{metric.value}</div>
                  {metric.subtitle && <p className="card-subtitle" style={{ margin: '0.3rem 0 0' }}>{metric.subtitle}</p>}
                </div>
              ))}
            </div>
          )}
        </CardBody>
      </Card>
    </section>
  )
}

import { useEffect, useMemo, useState } from 'react'
import {
  Area,
  AreaChart,
  CartesianGrid,
  Legend,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts'
import { SvgIcon } from '@progress/kendo-react-common'
import {
  arrowDownIcon,
  arrowUpIcon,
  banknoteOutlineIcon,
  fileReportIcon,
  minusIcon,
  walletOutlineIcon,
} from '@progress/kendo-svg-icons'
import { SkeletonKpiGrid } from '../../components/SkeletonCard'
import {
  dashboardService,
  type ChartDataResponse,
  type DepartmentBudgetItem,
  type MetricDto,
} from '../../services/dashboardService'
import { convertCurrencyText, formatCurrencyCompact, formatMoney, useDisplayCurrency } from '../../store/currencyStore'

// ── Types ─────────────────────────────────────────────────────────────────────
type DeptStatus = 'on-track' | 'over' | 'under'

interface AreaChartData {
  month: string
  revenue: number
  expenses: number
}

const STATUS_CONFIG: Record<DeptStatus, { label: string; cls: string }> = {
  'on-track': { label: 'Within budget', cls: 'av2-pill--green' },
  'over':     { label: 'Over budget',   cls: 'av2-pill--red'   },
  'under':    { label: 'Under budget',  cls: 'av2-pill--amber' },
}

// ── Helpers ───────────────────────────────────────────────────────────────────
const kpiWatermarkIcon = (title: string) => {
  const t = title.toLowerCase()
  if (t.includes('expense')) return walletOutlineIcon
  if (t.includes('net'))     return fileReportIcon
  return banknoteOutlineIcon
}

const trendPillCls = (direction?: string) => {
  const d = (direction ?? '').toLowerCase()
  if (d === 'up')   return 'av2-kpi-trend--positive'
  if (d === 'down') return 'av2-kpi-trend--negative'
  return 'av2-kpi-trend--neutral'
}

const trendIco = (direction?: string) => {
  const d = (direction ?? '').toLowerCase()
  if (d === 'up')   return arrowUpIcon
  if (d === 'down') return arrowDownIcon
  return minusIcon
}

const currFmt = (v: string) => convertCurrencyText(v, 'PHP')

const getDeptStatus = (utilizationPct: number): DeptStatus => {
  if (utilizationPct > 100) return 'over'
  if (utilizationPct < 75) return 'under'
  return 'on-track'
}

// ── KPI Card ──────────────────────────────────────────────────────────────────
const Av2KpiCard = ({ metric }: { metric: MetricDto }) => {
  const trendDir = (metric.trendDirection ?? '').toLowerCase()
  let fallbackTrend = 'Stable'
  if (trendDir === 'up')   fallbackTrend = 'Up vs Last Month'
  if (trendDir === 'down') fallbackTrend = 'Down vs Last Month'
  const trendText = metric.trendValue ? `${metric.trendValue} vs Last Month` : fallbackTrend

  return (
    <article className="av2-kpi-card" title="Read-only — no drill-down available">
      {/* Faded watermark icon */}
      <span className="av2-kpi-watermark" aria-hidden="true">
        <SvgIcon icon={kpiWatermarkIcon(metric.title)} />
      </span>

      <div className="av2-kpi-header">
        <p className="av2-kpi-title">{metric.title.toUpperCase()}</p>
        <span className="av2-kpi-readonly">READ-ONLY</span>
      </div>

      <div className="av2-kpi-value">{currFmt(metric.value)}</div>

      <span className={`av2-kpi-trend ${trendPillCls(metric.trendDirection)}`}>
        <SvgIcon icon={trendIco(metric.trendDirection)} />
        {trendText}
      </span>
    </article>
  )
}

// ── Department Performance Row ────────────────────────────────────────────────
const Av2DeptBar = ({ name, budget, actual, remaining, utilizationPct }: DepartmentBudgetItem) => {
  const status = getDeptStatus(utilizationPct)
  const config = STATUS_CONFIG[status]
  const barPct = Math.min(utilizationPct, 100)

  return (
    <div className="av2-dept-item">
      <div className="av2-dept-header">
        <span className="av2-dept-name">{name}</span>
        <div className="av2-dept-right">
          <span className={`av2-pill ${config.cls}`}>{config.label}</span>
          <span className="av2-dept-pct">{utilizationPct.toFixed(1)}%</span>
        </div>
      </div>
      <div className="av2-dept-track">
        <div
          className="av2-dept-bar"
          style={{
            width: `${barPct}%`,
            backgroundColor:
              utilizationPct > 100 ? '#EF4444'
              : utilizationPct < 75 ? '#F59E0B'
              : '#22C55E',
          }}
        />
      </div>
      <div className="av2-dept-meta">
        <span>{formatMoney(actual, 'PHP', { maximumFractionDigits: 0 })} used</span>
        <span>{formatMoney(budget, 'PHP', { maximumFractionDigits: 0 })} budget</span>
        <span>{formatMoney(remaining, 'PHP', { maximumFractionDigits: 0 })} remaining</span>
      </div>
    </div>
  )
}

// ── Main Dashboard ────────────────────────────────────────────────────────────
export const AuthorizedViewerDashboard = () => {
  const displayCurrency = useDisplayCurrency()

  const [metrics, setMetrics] = useState<MetricDto[]>([])
  const [chartData, setChartData] = useState<ChartDataResponse | null>(null)
  const [deptBudget, setDeptBudget] = useState<DepartmentBudgetItem[]>([])
  const [loading, setLoading] = useState(true)
  const [errors, setErrors] = useState<string[]>([])

  useEffect(() => {
    let cancelled = false

    const load = async () => {
      setLoading(true)
      const failures: string[] = []

      const [mr, cr, dr] = await Promise.allSettled([
        dashboardService.getMetrics('authorized-viewer'),
        dashboardService.getChartData(),
        dashboardService.getDepartmentBudget(),
      ])

      if (cancelled) return

      if (mr.status === 'fulfilled') setMetrics(mr.value.metrics)
      else failures.push('metrics')

      if (cr.status === 'fulfilled') setChartData(cr.value)
      else failures.push('chart data')

      if (dr.status === 'fulfilled') setDeptBudget(dr.value.items)
      else failures.push('department budget')

      setErrors(failures)
      setLoading(false)
    }

    void load()

    return () => {
      cancelled = true
    }
  }, [])

  // Show only Revenue, Expenses, Net Income (first 3)
  const displayMetrics = metrics.slice(0, 3)

  const areaData = useMemo<AreaChartData[]>(() => {
    if (!chartData?.data?.length) return []
    return chartData.data.map((d) => ({
      month: d.label,
      revenue: d.series.find((s) => s.name === 'Revenue')?.values[0] ?? 0,
      expenses: d.series.find((s) => s.name === 'Expenses')?.values[0] ?? 0,
    }))
  }, [chartData])

  const yAxisTickFormatter = useMemo(
    () => (value: number) => formatCurrencyCompact(value, 'PHP'),
    [displayCurrency],
  )

  const tooltipValueFormatter = useMemo(
    () => (value: unknown, name: unknown) => {
      const numericValue = Array.isArray(value) ? Number(value[0]) || 0 : Number(value) || 0
      return [
        formatMoney(numericValue, 'PHP', { maximumFractionDigits: 0 }),
        String(name ?? ''),
      ] as [string, string]
    },
    [displayCurrency],
  )

  const now = new Date()
  const periodLabel = now.toLocaleString('en-US', { month: 'long', year: 'numeric' })

  return (
    <section className="dashboard-scene av2-exec-scene">

      {/* ── Hero ────────────────────────────────────────────────── */}
      <div className="av2-hero">
        <div className="av2-hero-left">
          <h1 className="av2-hero-title">Executive Dashboard</h1>
          <span className="av2-badge-viewer">
            {/* Shield-check inline SVG */}
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
              <path d="M12 1L3 5v6c0 5.55 3.84 10.74 9 12 5.16-1.26 9-6.45 9-12V5l-9-4zm-2 16-4-4 1.41-1.41L10 14.17l6.59-6.59L18 9l-8 8z"/>
            </svg>
            Authorized Viewer
          </span>
        </div>
        <div className="av2-hero-right">
          <div className="av2-period-box">
            {/* Calendar SVG */}
            <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
              <rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
            </svg>
            <span>{periodLabel} — Month-to-Date</span>
            {/* Chevron SVG */}
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" aria-hidden="true">
              <polyline points="6 9 12 15 18 9"/>
            </svg>
          </div>
          <span className="av2-badge-confidential">Confidential — Authorized Viewers Only</span>
        </div>
      </div>

      {errors.length > 0 && (
        <p className="av2-card-sub" style={{ color: '#d32f2f', marginBottom: '1rem' }}>
          Some sections unavailable: {errors.join(', ')}.
        </p>
      )}

      {/* ── KPI Cards ───────────────────────────────────────────── */}
      {loading ? (
        <SkeletonKpiGrid count={3} />
      ) : (
        <div className="av2-kpi-grid">
          {displayMetrics.map((m) => (
            <Av2KpiCard key={m.title} metric={m} />
          ))}
        </div>
      )}

      {/* ── Bottom row: Area chart + Dept Performance ───────────── */}
      {!loading && (
        <div className="av2-charts-row">

          {/* Area Chart */}
          <div className="av2-panel">
            <h2 className="av2-panel-title">Revenue vs Expenses — Last 6 Months</h2>
            {areaData.length === 0 ? (
              <p style={{ padding: '2rem', textAlign: 'center', color: 'var(--muted)' }}>
                No live chart data available.
              </p>
            ) : (
              <ResponsiveContainer key={`revenue-expenses-${displayCurrency}`} width="100%" height={280}>
                <AreaChart data={areaData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                  <defs>
                    <linearGradient id="av2GradRevenue" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%"  stopColor="#1D63C1" stopOpacity={0.25} />
                      <stop offset="95%" stopColor="#1D63C1" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="av2GradExpenses" x1="0" y1="0" x2="0" y2="1">
