const formatCurrency = (value: number) => formatMoney(value, 'PHP')

const getFileNameFromDisposition = (disposition: string | undefined, fallback: string) => {
  if (!disposition) return fallback
  const utf8Match = disposition.match(/filename\*=UTF-8''([^;]+)/i)
  if (utf8Match?.[1]) return decodeURIComponent(utf8Match[1])
  // eslint-disable-next-line no-useless-escape
  const asciiMatch = disposition.match(/filename="?([^\";]+)"?/i)
  return asciiMatch?.[1] ?? fallback
}

const extractApiErrorMessage = (error: unknown): string => {
  if (typeof error !== 'object' || error === null) {
    return ''
  }

  const apiError = error as {
    message?: string
    response?: {
      data?: unknown
    }
  }

  const responseData = apiError.response?.data
  if (typeof responseData === 'string' && responseData.trim().length > 0) {
    return responseData.trim()
  }

  if (typeof responseData === 'object' && responseData !== null) {
    const responseObject = responseData as { message?: unknown; title?: unknown }
    if (typeof responseObject.message === 'string' && responseObject.message.trim().length > 0) {
      return responseObject.message.trim()
    }
    if (typeof responseObject.title === 'string' && responseObject.title.trim().length > 0) {
      return responseObject.title.trim()
    }
  }

  if (typeof apiError.message === 'string' && apiError.message.trim().length > 0) {
    return apiError.message.trim()
  }

  return ''
}

const toFriendlyJournalSaveError = (detail: string, entryDate: string): string => {
  const normalized = detail.trim().toLowerCase()

  if (normalized.includes('open fiscal period')) {
    return `Entry date ${entryDate} is not in an open fiscal period. Open or reopen the period from Manage Fiscal Periods, or choose a date within an open period.`
  }

  if (normalized.includes('invalid or inactive')) {
    return 'One or more selected accounts are invalid or inactive. Update the affected journal lines and try again.'
  }

  if (normalized.includes('balanced')) {
    return 'Journal is not balanced. Make sure total debits equal total credits before saving.'
  }

  return detail
}

const getJournalFormIssues = (
  journalForm: { date: string; reference: string; description: string },
  journalLines: JournalLineForm[],
) => {
  const issues: string[] = []

  if (!journalForm.date.trim()) {
    issues.push('Date is required.')
  }

  if (!journalForm.reference.trim()) {
    issues.push('Reference is required.')
  }

  if (!journalForm.description.trim()) {
    issues.push('Description is required.')
  }

  const debitLinesWithAmount = journalLines.filter((line) => line.side === 'debit' && Number(line.amount || 0) > 0)
  const creditLinesWithAmount = journalLines.filter((line) => line.side === 'credit' && Number(line.amount || 0) > 0)

  if (debitLinesWithAmount.length === 0) {
    issues.push('At least one debit line with an amount is required.')
  }

  if (creditLinesWithAmount.length === 0) {
    issues.push('At least one credit line with an amount is required.')
  }

  const lineWithMissingAccount = journalLines.find((line) => Number(line.amount || 0) > 0 && !line.accountId)
  if (lineWithMissingAccount) {
    issues.push('Each line with an amount must have an account selected.')
  }

  const lineWithMissingAmount = journalLines.find((line) => line.accountId && Number(line.amount || 0) <= 0)
  if (lineWithMissingAmount) {
    issues.push('Each selected account must have an amount greater than zero.')
  }

  return issues
}

const createDefaultJournalLine = (side: 'debit' | 'credit'): JournalLineForm => ({
  id: createClientId(),
  side,
  accountId: '',
  description: '',
  amount: '',
})

const resolveAccountTypeCode = (type: number | string) => {
  if (typeof type === 'number') {
    return type
  }

  const parsed = Number(type)
  if (!Number.isNaN(parsed)) {
    return parsed
  }

  switch (String(type).toLowerCase()) {
    case 'asset':
      return 1
    case 'liability':
      return 2
    case 'equity':
      return 3
    case 'revenue':
      return 4
    case 'expense':
      return 5
    default:
      return 0
  }
}

const normalizeJournalStatus = (status: string | number) => {
  const raw = String(status ?? '').trim().toLowerCase()
  if (raw === '1' || raw === 'draft') return 'Draft'
  if (raw === '2' || raw === 'posted') return 'Posted'
  return 'Unknown'
}

const monthLabel = (year: number, month: number) => {
  const dt = new Date(year, month - 1, 1)
  return dt.toLocaleString(undefined, { month: 'long', year: 'numeric' })
}

const applyAccountNumberMask = (rawValue: string, sample: string) => {
  const digitsOnly = rawValue.replaceAll(/\D/g, '')
  const sampleChars = sample.split('')
  const maxDigits = sampleChars.filter((ch) => /\d/.test(ch)).length
  const digits = digitsOnly.slice(0, maxDigits)

  let digitIndex = 0
  let output = ''

  for (const ch of sampleChars) {
    if (/\d/.test(ch)) {
      if (digitIndex >= digits.length) break
      output += digits[digitIndex]
      digitIndex += 1
      continue
    }

    if (digitIndex > 0 && digitIndex < digits.length) {
      output += ch
    }
  }

  return output
}

const isValidAccountNumberByPattern = (value: string, pattern: string) => {
  try {
    return new RegExp(pattern).test(value.trim())
  } catch {
    return false
  }
}

const canCompilePattern = (pattern: string) => {
  try {
    new RegExp(pattern)
    return true
  } catch {
    return false
  }
}

