  const payableRows = useMemo(
    () => payables.map((item) => ({ ...item, invoiceAmountText: formatCurrency(item.invoiceAmount), poAmountText: formatCurrency(item.poAmount), receiptAmountText: formatCurrency(item.receiptAmount) })),
