        const unmatchedCount = selectedStatementId ? unmatched.length : aggregateUnmatchedCount
        const kpiAccent = unmatchedCount === 0 ? 'accent-green' : unmatchedCount <= 10 ? 'accent-amber' : 'accent-red'

