import { useEffect, useState } from 'react'
import { Button } from '@progress/kendo-react-buttons'
import { Input, type InputChangeEvent } from '@progress/kendo-react-inputs'
import { DashboardCard } from '../../components/DashboardCard'
import { bankDirectoryService, type BankDirectoryItem } from '../../services/bankDirectoryService'
import { useNotificationStore } from '../../store/notificationStore'

const toText = (value: unknown) => (typeof value === 'string' ? value : '')

const defaultAccountPattern = String.raw`^\d{4}-\d{4}-\d{2}$`
type BankStatusFilter = 'all' | 'active' | 'removed'

const toDateLabel = (value?: string | null) => {
  if (!value) return '-'
  const dt = new Date(value)
  return Number.isNaN(dt.getTime()) ? '-' : dt.toLocaleString()
}

const extractApiMessage = (error: unknown, fallback: string) => {
  if (typeof error !== 'object' || error === null) return fallback
  const payload = error as {
    response?: { data?: { message?: string } | string }
    message?: string
  }

  const raw = payload.response?.data
  if (typeof raw === 'string' && raw.trim()) return raw.trim()
  if (typeof raw === 'object' && raw && typeof raw.message === 'string' && raw.message.trim()) {
    return raw.message.trim()
  }
  if (typeof payload.message === 'string' && payload.message.trim()) return payload.message.trim()
  return fallback
}

export const BankDirectoryModule = () => {
  const push = useNotificationStore((state) => state.push)
  const [loading, setLoading] = useState(false)
  const [banks, setBanks] = useState<BankDirectoryItem[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(1)
  const [pageSize] = useState(10)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState<BankStatusFilter>('all')
  const [editingId, setEditingId] = useState<string | null>(null)
  const [editForm, setEditForm] = useState({
    name: '',
    country: 'Philippines',
    branchName: '',
    accountNumberPattern: '',
    accountNumberSample: '',
  })
  const [form, setForm] = useState({
    name: '',
    country: 'Philippines',
    branchName: '',
    accountNumberPattern: defaultAccountPattern,
    accountNumberSample: '1234-5678-90',
  })

  const loadBanks = async (targetPage = page, searchTerm = search) => {
    setLoading(true)
    try {
      const response = await bankDirectoryService.getAllBanks({
        search: searchTerm.trim() || undefined,
        status: statusFilter,
        page: targetPage,
        pageSize,
      })

      setBanks(response.data.items ?? [])
      setTotal(response.data.total ?? 0)
      setPage(targetPage)
    } catch {
      push('error', 'Unable to load bank directory.')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    void loadBanks(1)
  }, [statusFilter, search])

  const addBank = async () => {
    if (!form.name.trim() || !form.accountNumberPattern.trim() || !form.accountNumberSample.trim()) {
      push('warning', 'Bank name, account number format rule, and sample account number are required.')
      return
    }

    try {
      await bankDirectoryService.createBank({
        name: form.name.trim(),
        country: form.country.trim(),
        branchName: form.branchName.trim() || undefined,
        accountNumberPattern: form.accountNumberPattern.trim(),
        accountNumberSample: form.accountNumberSample.trim(),
      })
      push('success', 'Bank saved successfully.')
      setForm({
        name: '',
        country: 'Philippines',
        branchName: '',
        accountNumberPattern: defaultAccountPattern,
        accountNumberSample: '1234-5678-90',
      })
      await loadBanks(1)
    } catch (error) {
      push('error', extractApiMessage(error, 'Failed to save bank.'))
    }
  }

  const startEdit = (bank: BankDirectoryItem) => {
    setEditingId(bank.id)
    setEditForm({
      name: bank.name,
      country: bank.country,
      branchName: bank.branchName ?? '',
      accountNumberPattern: bank.accountNumberPattern,
      accountNumberSample: bank.accountNumberSample,
    })
  }

  const saveEdit = async (id: string) => {
    if (!editForm.name.trim() || !editForm.accountNumberPattern.trim() || !editForm.accountNumberSample.trim()) {
      push('warning', 'Bank name, account number format rule, and sample account number are required.')
      return
    }

    try {
      await bankDirectoryService.updateBank(id, {
        name: editForm.name.trim(),
        country: editForm.country.trim(),
        branchName: editForm.branchName.trim() || undefined,
        accountNumberPattern: editForm.accountNumberPattern.trim(),
        accountNumberSample: editForm.accountNumberSample.trim(),
      })
      push('success', 'Bank updated successfully.')
      setEditingId(null)
      await loadBanks(page)
    } catch (error) {
      push('error', extractApiMessage(error, 'Failed to update bank.'))
    }
  }

  const removeBank = async (bank: BankDirectoryItem) => {
    if (!bank.isActive) return
    if (!confirm(`Remove bank "${bank.name}" from active list?`)) return

    try {
      await bankDirectoryService.removeBank(bank.id)
      push('success', 'Bank removed successfully.')
      await loadBanks(page)
    } catch (error) {
      push('error', extractApiMessage(error, 'Failed to remove bank.'))
    }
  }

  const restoreBank = async (bank: BankDirectoryItem) => {
    if (bank.isActive) return

    try {
      await bankDirectoryService.restoreBank(bank.id)
      push('success', 'Bank restored successfully.')
      await loadBanks(page)
    } catch (error) {
      push('error', extractApiMessage(error, 'Failed to restore bank.'))
    }
  }

  const totalPages = Math.max(1, Math.ceil(total / pageSize))

  return (
    <section className="accountant-module">
      <header className="card-header" style={{ marginBottom: '0.75rem' }}>
        <h1 className="page-title">Bank Directory</h1>
        <p className="card-subtitle">Manage active banks and account number format rules for statement imports.</p>
      </header>

      <DashboardCard title="Directory Overview" subtitle="Register banks and define account number format rules by bank and branch.">
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr 1fr auto', gap: '10px', alignItems: 'end' }}>
          <div>
            <label htmlFor="bank-directory-name">Bank Name</label>
            <Input
              id="bank-directory-name"
              placeholder="e.g. Metrobank"
              value={form.name}
              onChange={(e: InputChangeEvent) => setForm((curr) => ({ ...curr, name: toText(e.value) }))}
            />
          </div>
          <div>
            <label htmlFor="bank-directory-country">Country</label>
            <Input
              id="bank-directory-country"
              placeholder="e.g. Philippines"
              value={form.country}
              onChange={(e: InputChangeEvent) => setForm((curr) => ({ ...curr, country: toText(e.value) }))}
            />
          </div>
          <div>
            <label htmlFor="bank-directory-branch">Branch</label>
            <Input
              id="bank-directory-branch"
              placeholder="e.g. Makati Main"
              value={form.branchName}
              onChange={(e: InputChangeEvent) => setForm((curr) => ({ ...curr, branchName: toText(e.value) }))}
            />
          </div>
          <div>
            <label htmlFor="bank-directory-pattern">Account Number Format Rule</label>
            <Input
              id="bank-directory-pattern"
              placeholder="Use the format pattern (advanced)"
              value={form.accountNumberPattern}
              onChange={(e: InputChangeEvent) => setForm((curr) => ({ ...curr, accountNumberPattern: toText(e.value) }))}
            />
            <div style={{ color: 'var(--text-muted)', fontSize: '0.82rem', marginTop: '4px' }}>
              This rule checks if the account number follows your sample format.
            </div>
          </div>
          <div>
            <label htmlFor="bank-directory-sample">Sample Account Number</label>
            <Input
              id="bank-directory-sample"
              placeholder="1234-5678-90"
              value={form.accountNumberSample}
              onChange={(e: InputChangeEvent) => setForm((curr) => ({ ...curr, accountNumberSample: toText(e.value) }))}
            />
          </div>
          <Button themeColor="primary" onClick={() => void addBank()}>Add Bank</Button>
        </div>
      </DashboardCard>

      <DashboardCard title="Banks" subtitle="Listed/removed timeline and account format details">
        <div style={{ display: 'flex', gap: '8px', marginBottom: '10px', flexWrap: 'wrap' }}>
          <Input
            placeholder="Search bank name"
            value={search}
            onChange={(e: InputChangeEvent) => setSearch(toText(e.value))}
            style={{ width: 280 }}
          />
          <select
            className="k-input k-input-md"
            style={{ height: 36, minWidth: 160 }}
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value as BankStatusFilter)}
          >
            <option value="all">All statuses</option>
            <option value="active">Active only</option>
            <option value="removed">Removed only</option>
          </select>
        </div>

        {loading && <div style={{ color: 'var(--text-muted)' }}>Loading banks...</div>}
        {!loading && banks.length === 0 && <div style={{ color: 'var(--text-muted)' }}>No banks available.</div>}

        {!loading && banks.length > 0 && (
          <div style={{ overflowX: 'auto' }}>
            <table className="budget-table" style={{ minWidth: 980 }}>
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Country</th>
                  <th>Branch</th>
                  <th>Status</th>
                  <th>Format Rule</th>
                  <th>Sample Account</th>
                  <th>Listed</th>
                  <th>Removed</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {banks.map((bank) => (
                  <tr key={bank.id}>
                    <td>
                      {editingId === bank.id ? (
                        <Input value={editForm.name} onChange={(e: InputChangeEvent) => setEditForm((curr) => ({ ...curr, name: toText(e.value) }))} />
                      ) : bank.name}
                    </td>
                    <td>
                      {editingId === bank.id ? (
                        <Input value={editForm.country} onChange={(e: InputChangeEvent) => setEditForm((curr) => ({ ...curr, country: toText(e.value) }))} />
                      ) : bank.country}
                    </td>
                    <td>
                      {editingId === bank.id ? (
                        <Input value={editForm.branchName} onChange={(e: InputChangeEvent) => setEditForm((curr) => ({ ...curr, branchName: toText(e.value) }))} />
                      ) : (bank.branchName || '-')}
                    </td>
                    <td>{bank.isActive ? 'Active' : 'Removed'}</td>
                    <td>
                      {editingId === bank.id ? (
                        <Input value={editForm.accountNumberPattern} onChange={(e: InputChangeEvent) => setEditForm((curr) => ({ ...curr, accountNumberPattern: toText(e.value) }))} />
                      ) : bank.accountNumberPattern}
                    </td>
                    <td>
                      {editingId === bank.id ? (
                        <Input value={editForm.accountNumberSample} onChange={(e: InputChangeEvent) => setEditForm((curr) => ({ ...curr, accountNumberSample: toText(e.value) }))} />
                      ) : bank.accountNumberSample}
                    </td>
                    <td>{toDateLabel(bank.listedAtUtc)} by {bank.listedBy}</td>
                    <td>{bank.removedAtUtc ? `${toDateLabel(bank.removedAtUtc)} by ${bank.removedBy ?? '-'}` : '-'}</td>
                    <td>
                      <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                        {editingId === bank.id ? (
                          <>
                            <Button themeColor="primary" onClick={() => void saveEdit(bank.id)}>Save</Button>
                            <Button onClick={() => setEditingId(null)}>Cancel</Button>
                          </>
                        ) : (
                          <Button onClick={() => startEdit(bank)}>Edit</Button>
                        )}

                        {bank.isActive ? (
                          <Button onClick={() => void removeBank(bank)}>Remove</Button>
                        ) : (
                          <Button onClick={() => void restoreBank(bank)}>Restore</Button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {!loading && total > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: '10px' }}>
            <div style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>
              Showing page {page} of {totalPages} ({total} result(s))
            </div>
            <div style={{ display: 'flex', gap: '6px' }}>
              <Button disabled={page <= 1} onClick={() => void loadBanks(page - 1)}>Previous</Button>
              <Button disabled={page >= totalPages} onClick={() => void loadBanks(page + 1)}>Next</Button>
            </div>
          </div>
        )}
      </DashboardCard>
    </section>
  )
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import { Button } from '@progress/kendo-react-buttons'
import { Dialog, DialogActionsBar } from '@progress/kendo-react-dialogs'
import { Input, type InputChangeEvent } from '@progress/kendo-react-inputs'
import type { ColumnDef } from '@tanstack/react-table'
import { DashboardCard } from '../../components/DashboardCard'
import { DataTable } from '../../components/ui/data-table'
import { customerService, type Customer } from '../../services/vendorCustomerService'
import { useAuthStore } from '../../store/authStore'
import { useNotificationStore } from '../../store/notificationStore'
import {
  createCustomerSchema,
  updateCustomerSchema,
  type CreateCustomerInput,
  type UpdateCustomerInput,
} from '../../schemas/vendorCustomerSchemas'

interface CustomerFormData {
  customerCode: string
  name: string
  contactPerson: string
  email: string
  phoneNumber: string
  address: string
  city: string
  state: string
  postalCode: string
  country: string
  taxId: string
  creditLimit: string
  paymentTerms: string
  isActive: boolean
}

const defaultFormData: CustomerFormData = {
  customerCode: '',
  name: '',
  contactPerson: '',
  email: '',
  phoneNumber: '',
  address: '',
  city: '',
  state: '',
  postalCode: '',
  country: '',
  taxId: '',
  creditLimit: '',
  paymentTerms: '',
  isActive: true,
}

const formatCurrency = (value: number) =>
  new Intl.NumberFormat('en-PH', {
    style: 'currency',
    currency: 'PHP',
  }).format(value)

export function CustomersModule() {
  const { user } = useAuthStore()
  const push = useNotificationStore((state) => state.push)

  const [customers, setCustomers] = useState<Customer[]>([])
  const [loading, setLoading] = useState(false)
  const [showDialog, setShowDialog] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [formData, setFormData] = useState<CustomerFormData>(defaultFormData)
  const [formErrors, setFormErrors] = useState<Record<string, string>>({})
  const [searchText, setSearchText] = useState('')

  const loadCustomers = useCallback(async () => {
    try {
      setLoading(true)
      const response = await customerService.getCustomers()
      setCustomers(response.data)
    } catch {
      push('error', 'Failed to load customers')
    } finally {
      setLoading(false)
    }
  }, [push])

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    loadCustomers()
  }, [loadCustomers])

  const filteredCustomers = searchText
    ? customers.filter(
        (c) =>
          c.customerCode.toLowerCase().includes(searchText.toLowerCase()) ||
          c.name.toLowerCase().includes(searchText.toLowerCase()),
      )
    : customers

  const customerColumns = useMemo<ColumnDef<Customer>[]>(
    () => [
      { accessorKey: 'customerCode', header: 'Code' },
      { accessorKey: 'name', header: 'Customer Name' },
      { accessorKey: 'contactPerson', header: 'Contact' },
      { accessorKey: 'city', header: 'City' },
      { accessorKey: 'country', header: 'Country' },
      {
        id: 'creditLimit',
        header: 'Credit Limit',
        cell: ({ row }) => formatCurrency(row.original.creditLimit),
      },
      {
        id: 'isActive',
        header: 'Active',
        cell: ({ row }) => (row.original.isActive ? 'Yes' : 'No'),
      },
      {
        id: 'actions',
        header: 'Actions',
        cell: ({ row }) => (
          <div className="flex gap-2">
            <Button
              icon="edit"
              onClick={() => handleEditClick(row.original)}
              style={{ marginRight: '8px' }}
            />
            <Button icon="delete" onClick={() => handleDeleteClick(row.original)} />
          </div>
        ),
      },
    ],
    [],
  )

  const handleAddClick = () => {
    setEditingId(null)
    setFormData(defaultFormData)
    setFormErrors({})
    setShowDialog(true)
  }

  const handleEditClick = (customer: Customer) => {
    setEditingId(customer.id)
    setFormData({
      customerCode: customer.customerCode,
      name: customer.name,
      contactPerson: customer.contactPerson || '',
      email: customer.email || '',
      phoneNumber: customer.phoneNumber || '',
      address: customer.address || '',
      city: customer.city || '',
      state: customer.state || '',
      postalCode: customer.postalCode || '',
      country: customer.country || '',
      taxId: customer.taxId || '',
      creditLimit: customer.creditLimit.toString(),
      paymentTerms: customer.paymentTerms || '',
      isActive: customer.isActive,
    })
    setFormErrors({})
    setShowDialog(true)
  }

  const handleDeleteClick = async (customer: Customer) => {
    if (confirm(`Delete customer "${customer.name}"?`)) {
      try {
        await customerService.deleteCustomer(customer.id)
        push('success', 'Customer deleted successfully')
        await loadCustomers()
      } catch {
        push('error', 'Failed to delete customer')
      }
    }
  }

  const handleFormChange = (e: InputChangeEvent | React.ChangeEvent<HTMLInputElement>) => {
    const target = e.target as HTMLInputElement
    const { name, value, type, checked } = target
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }))
    // Clear error for this field
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const newErrors = { ...prev }
        delete newErrors[name]
        return newErrors
      })
    }
  }

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {}
    const submitData = {
      customerCode: formData.customerCode,
      name: formData.name,
      contactPerson: formData.contactPerson ? formData.contactPerson : undefined,
      email: formData.email ? formData.email : undefined,
      phoneNumber: formData.phoneNumber ? formData.phoneNumber : undefined,
      address: formData.address ? formData.address : undefined,
      city: formData.city ? formData.city : undefined,
      state: formData.state ? formData.state : undefined,
      postalCode: formData.postalCode ? formData.postalCode : undefined,
      country: formData.country ? formData.country : undefined,
      taxId: formData.taxId ? formData.taxId : undefined,
      creditLimit: parseFloat(formData.creditLimit) || 0,
      paymentTerms: formData.paymentTerms ? formData.paymentTerms : undefined,
      ...(editingId && { isActive: formData.isActive }),
    }

    const schema = editingId ? updateCustomerSchema : createCustomerSchema
    const result = schema.safeParse(submitData)

    if (!result.success) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      result.error.issues.forEach((err: any) => {
        if (err.path[0]) {
          errors[err.path[0].toString()] = err.message
        }
      })
      setFormErrors(errors)
      return false
    }

    return true
  }

  const handleSave = async () => {
    if (!validateForm()) {
      return
    }

    try {
      const baseData: CreateCustomerInput = {
        customerCode: formData.customerCode,
        name: formData.name,
        contactPerson: formData.contactPerson ? formData.contactPerson : undefined,
        email: formData.email ? formData.email : undefined,
        phoneNumber: formData.phoneNumber ? formData.phoneNumber : undefined,
        address: formData.address ? formData.address : undefined,
        city: formData.city ? formData.city : undefined,
        state: formData.state ? formData.state : undefined,
        postalCode: formData.postalCode ? formData.postalCode : undefined,
        country: formData.country ? formData.country : undefined,
        taxId: formData.taxId ? formData.taxId : undefined,
        creditLimit: parseFloat(formData.creditLimit) || 0,
        paymentTerms: formData.paymentTerms ? formData.paymentTerms : undefined,
      }

      if (editingId) {
        const updateData: UpdateCustomerInput = {
          ...baseData,
          isActive: formData.isActive,
        }
        await customerService.updateCustomer(editingId, updateData)
        push('success', 'Customer updated successfully')
      } else {
        await customerService.createCustomer(baseData)
        push('success', 'Customer created successfully')
      }

      setShowDialog(false)
      await loadCustomers()
    } catch {
      push('error', editingId ? 'Failed to update customer' : 'Failed to create customer')
    }
  }

  const handleDialogClose = () => {
    setShowDialog(false)
    setFormErrors({})
  }

  return (
    <div className="space-y-4 p-4">
      <DashboardCard
        title="Customer Management"
        subtitle="Create, update, and manage customer master data for accounts receivable"
      >
        <div className="space-y-4">
          <div className="flex items-center justify-between gap-4">
            <Input
              placeholder="Search by code or name..."
              value={searchText}
              onChange={(e: InputChangeEvent) => setSearchText((e.target.value as string) || '')}
              style={{ width: '300px' }}
            />
            <Button
              themeColor="primary"
              onClick={handleAddClick}
              disabled={!user || !['accountant', 'cfo', 'super-admin'].includes(user.role)}
            >
              + Add Customer
            </Button>
          </div>

          {loading && <div style={{ marginBottom: '12px', color: 'var(--text-muted)' }}>Loading customers...</div>}

          <DataTable data={filteredCustomers} columns={customerColumns} pageSizeOptions={[20, 50, 100]} />
        </div>
      </DashboardCard>

      {showDialog && (
        <Dialog title={editingId ? 'Edit Customer' : 'Add Customer'} onClose={handleDialogClose}>
          <div className="space-y-4 p-4" style={{ minWidth: '500px' }}>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium mb-1">Customer Code*</label>
                <Input
                  name="customerCode"
                  value={formData.customerCode}
                  onChange={handleFormChange}
                  disabled={editingId !== null}
                  className={formErrors.customerCode ? 'error' : ''}
                />
                {formErrors.customerCode && <p className="text-red-500 text-xs">{formErrors.customerCode}</p>}
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Customer Name*</label>
                <Input
                  name="name"
                  value={formData.name}
                  onChange={handleFormChange}
                  className={formErrors.name ? 'error' : ''}
                />
                {formErrors.name && <p className="text-red-500 text-xs">{formErrors.name}</p>}
              </div>
            </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Contact Person</label>
              <Input name="contactPerson" value={formData.contactPerson} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Email</label>
              <Input name="email" value={formData.email} onChange={handleFormChange} type="email" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Phone</label>
              <Input name="phoneNumber" value={formData.phoneNumber} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Tax ID</label>
              <Input name="taxId" value={formData.taxId} onChange={handleFormChange} />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">Address</label>
            <Input name="address" value={formData.address} onChange={handleFormChange} />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">City</label>
              <Input name="city" value={formData.city} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">State</label>
              <Input name="state" value={formData.state} onChange={handleFormChange} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Postal Code</label>
              <Input name="postalCode" value={formData.postalCode} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Country</label>
              <Input name="country" value={formData.country} onChange={handleFormChange} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Credit Limit</label>
              <Input
                name="creditLimit"
                value={formData.creditLimit}
                onChange={handleFormChange}
                type="number"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Payment Terms</label>
              <Input name="paymentTerms" value={formData.paymentTerms} onChange={handleFormChange} />
            </div>
          </div>

            {editingId && (
              <label className="flex items-center gap-2">
                <input
                  type="checkbox"
                  name="isActive"
                  checked={formData.isActive}
                  onChange={handleFormChange}
                />
                <span className="text-sm font-medium">Active</span>
              </label>
            )}
          </div>

          <DialogActionsBar>
            <Button onClick={handleDialogClose}>Cancel</Button>
            <Button themeColor="primary" onClick={handleSave}>
              Save
            </Button>
          </DialogActionsBar>
        </Dialog>
      )}
    </div>
  )
}

