  </svg>
)

// ── Action Card ───────────────────────────────────────────────────────────────

interface ActionCardProps {
  icon: React.ReactNode
  title: string
  description: string
  onClick: () => void
}

const ActionCard = ({ icon, title, description, onClick }: ActionCardProps) => (
  <button
    type="button"
    onClick={onClick}
    style={{
      background: '#fff',
      border: '1px solid #e5e7eb',
      borderRadius: 12,
      padding: '24px 20px',
      textAlign: 'left',
      cursor: 'pointer',
      width: '100%',
      transition: 'box-shadow 0.15s',
    }}
    onMouseEnter={(e) => { (e.currentTarget as HTMLButtonElement).style.boxShadow = '0 4px 16px rgba(30,64,175,0.12)' }}
    onMouseLeave={(e) => { (e.currentTarget as HTMLButtonElement).style.boxShadow = 'none' }}
  >
    <div
      style={{
        width: 60,
        height: 60,
        borderRadius: 12,
        background: '#1d4ed8',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: '#fff',
        marginBottom: 14,
      }}
    >
      {icon}
    </div>
    <div style={{ fontWeight: 700, fontSize: 15, color: '#111827', marginBottom: 4 }}>{title}</div>
    <div style={{ fontSize: 13, color: '#6b7280' }}>{description}</div>
  </button>
)

// ── Shared result table ───────────────────────────────────────────────────────

const ResultTable = ({ columns, rows }: { columns: string[]; rows: Array<Record<string, string | number>> }) => (
  <div style={{ overflowX: 'auto', border: '1px solid #e5e7eb', borderRadius: 8, maxHeight: 420, overflowY: 'auto' }}>
    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
      <thead style={{ background: '#f8fafc', position: 'sticky', top: 0 }}>
        <tr>
          {columns.map((col) => (
            <th key={col} style={{ padding: '8px 12px', textAlign: 'left', fontWeight: 600, color: '#374151', borderBottom: '1px solid #e5e7eb', whiteSpace: 'nowrap' }}>{col}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.map((row) => {
          const rowKey = columns.map((c) => String(row[c] ?? '')).join('|')
          return (
            <tr key={rowKey} style={{ borderBottom: '1px solid #f3f4f6' }}>
              {columns.map((col) => (
                <td key={col} style={{ padding: '7px 12px', color: '#1f2937' }}>{String(row[col] ?? '')}</td>
              ))}
            </tr>
          )
        })}
      </tbody>
    </table>
  </div>
)

// ── Main Component ────────────────────────────────────────────────────────────

export const FinancialReportsModule = () => {
  useDisplayCurrency()
  const user = useAuthStore((state) => state.user)
  const push = useNotificationStore((state) => state.push)

  // Modal visibility
  const [showRunReport, setShowRunReport] = useState(false)
  const [showExport, setShowExport] = useState(false)
  const [showDrilldown, setShowDrilldown] = useState(false)
  const [showTemplateManager, setShowTemplateManager] = useState(false)
  const [showAuditLog, setShowAuditLog] = useState(false)
  const [showScheduler, setShowScheduler] = useState(false)

  // Run Report state
  const [rrType, setRrType] = useState<ReportType>('income-statement')
  const [rrStartDate, setRrStartDate] = useState(firstOfMonth)
  const [rrEndDate, setRrEndDate] = useState(today)
  const [rrAsOfDate, setRrAsOfDate] = useState(today)
  const [rrLoading, setRrLoading] = useState(false)
  const [rrResult, setRrResult] = useState<null | {
    rows: Array<Record<string, string | number>>
    columns: string[]
    summary?: Record<string, number>
  }>(null)

  // Export state
  const [expType, setExpType] = useState<ReportType>('income-statement')
  const [expFormat, setExpFormat] = useState<'excel' | 'pdf'>('excel')
  const [expStartDate, setExpStartDate] = useState(firstOfMonth)
  const [expEndDate, setExpEndDate] = useState(today)
  const [expAsOfDate, setExpAsOfDate] = useState(today)
  const [expLoading, setExpLoading] = useState(false)

  // Drill-down state
  const [ddType, setDdType] = useState<'aging-ap' | 'aging-ar' | 'department-budget'>('aging-ap')
  const [ddLoading, setDdLoading] = useState(false)
  const [ddAsOfDate, setDdAsOfDate] = useState(today)
  const [ddRows, setDdRows] = useState<Array<Record<string, string | number>>>([])
  const [ddColumns, setDdColumns] = useState<string[]>([])
  const [ddSummary, setDdSummary] = useState<Array<{ bucket: string; total: number }>>([])

  // Template management state
  const [templates, setTemplates] = useState<ReportTemplate[]>([])
  const [templatesLoading, setTemplatesLoading] = useState(false)
  const [templatesBusy, setTemplatesBusy] = useState(false)
  const [templateName, setTemplateName] = useState('')
  const [templateType, setTemplateType] = useState<ReportType>('income-statement')
  const [templateVisibility, setTemplateVisibility] = useState<'Private' | 'Team'>('Private')

  // Audit log state
  const [auditLogs, setAuditLogs] = useState<AuditActivity[]>([])
  const [auditLoading, setAuditLoading] = useState(false)

  // Scheduler state
  const [schedulerItems, setSchedulerItems] = useState<SchedulerItem[]>([])
  const [schedulerLoading, setSchedulerLoading] = useState(false)
  const [schedulerBusyId, setSchedulerBusyId] = useState<string | null>(null)
  const [schedulerCreateBusy, setSchedulerCreateBusy] = useState(false)
  const [newScheduleLabel, setNewScheduleLabel] = useState('')
  const [newScheduleType, setNewScheduleType] = useState<ReportType>('income-statement')
  const [newScheduleCadence, setNewScheduleCadence] = useState<ScheduleCadence>('Weekly')
  const [newScheduleTarget, setNewScheduleTarget] = useState<ScheduleTarget>('Excel')
  const [newScheduleActive, setNewScheduleActive] = useState(true)
  const [liveSummaryLoading, setLiveSummaryLoading] = useState(false)
  const [liveSummary, setLiveSummary] = useState({
    savedReports: 0,
    activeSchedules: 0,
    netIncome: 0,
    lastUpdated: '',
  })

  const rrIsDateRange = rrType === 'income-statement' || rrType === 'cash-flow'
  const rrIsBudget = rrType === 'department-budget'
  const expIsDateRange = expType === 'income-statement'

  // ── Run Report ──────────────────────────────────────────────────────────────

  const handleRunReport = useCallback(async () => {
    setRrLoading(true)
    setRrResult(null)
    try {
      let rows: Array<Record<string, string | number>> = []
      let columns: string[] = []
      let summary: Record<string, number> | undefined

      switch (rrType) {
        case 'income-statement': {
          const res = await reportsService.getIncomeStatement({ startDate: rrStartDate, endDate: rrEndDate })
          const data = res.data as {
            revenue: Array<{ accountCode: string; accountName: string; amount: number }>
            expenses: Array<{ accountCode: string; accountName: string; amount: number }>
            totalRevenue: number; totalExpenses: number; netIncome: number
          }
          columns = ['Section', 'Account Code', 'Account Name', 'Amount']
          rows = [
            ...data.revenue.map(r => ({ Section: 'Revenue', 'Account Code': r.accountCode, 'Account Name': r.accountName, Amount: formatCurrency(r.amount) })),
            ...data.expenses.map(r => ({ Section: 'Expense', 'Account Code': r.accountCode, 'Account Name': r.accountName, Amount: formatCurrency(r.amount) })),
          ]
          summary = { 'Total Revenue': data.totalRevenue, 'Total Expenses': data.totalExpenses, 'Net Income': data.netIncome }
          break
        }
        case 'balance-sheet': {
          const res = await reportsService.getBalanceSheet({ asOfDate: rrAsOfDate })
          const data = res.data as {
            assets: Array<{ accountCode: string; accountName: string; amount: number }>
            liabilities: Array<{ accountCode: string; accountName: string; amount: number }>
            equity: Array<{ accountCode: string; accountName: string; amount: number }>
            totalAssets: number; totalLiabilities: number; totalEquity: number
          }
          columns = ['Section', 'Account Code', 'Account Name', 'Balance']
          rows = [
            ...data.assets.map(r => ({ Section: 'Asset', 'Account Code': r.accountCode, 'Account Name': r.accountName, Balance: formatCurrency(r.amount) })),
            ...data.liabilities.map(r => ({ Section: 'Liability', 'Account Code': r.accountCode, 'Account Name': r.accountName, Balance: formatCurrency(r.amount) })),
            ...data.equity.map(r => ({ Section: 'Equity', 'Account Code': r.accountCode, 'Account Name': r.accountName, Balance: formatCurrency(r.amount) })),
          ]
          summary = { 'Total Assets': data.totalAssets, 'Total Liabilities': data.totalLiabilities, 'Total Equity': data.totalEquity }
          break
        }
        case 'cash-flow': {
          const res = await reportsService.getCashFlow({ startDate: rrStartDate, endDate: rrEndDate })
          const data = res.data as { operatingActivities: number; investingActivities: number; financingActivities: number; netCashFlow: number }
          columns = ['Activity', 'Amount']
          rows = [
            { Activity: 'Operating Activities', Amount: formatCurrency(data.operatingActivities) },
            { Activity: 'Investing Activities', Amount: formatCurrency(data.investingActivities) },
            { Activity: 'Financing Activities', Amount: formatCurrency(data.financingActivities) },
            { Activity: 'Net Cash Flow', Amount: formatCurrency(data.netCashFlow) },
          ]
          break
        }
        case 'aging-ap': {
          const res = await reportsService.getAgingAp({ asOfDate: rrAsOfDate })
          const data = res.data as { items: Array<{ invoiceNumber: string; vendorName: string; dueDate: string; totalAmount: number; bucket: string; ageDays: number; status: string }> }
          columns = ['Invoice #', 'Vendor', 'Due Date', 'Amount', 'Bucket', 'Age (days)', 'Status']
          rows = data.items.map(r => ({ 'Invoice #': r.invoiceNumber, Vendor: r.vendorName, 'Due Date': r.dueDate, Amount: formatCurrency(r.totalAmount), Bucket: r.bucket, 'Age (days)': r.ageDays, Status: r.status }))
          break
        }
        case 'aging-ar': {
          const res = await reportsService.getAgingAr({ asOfDate: rrAsOfDate })
          const data = res.data as { items: Array<{ invoiceNumber: string; customerName: string; dueDate: string; totalAmount: number; bucket: string; ageDays: number; status: string }> }
          columns = ['Invoice #', 'Customer', 'Due Date', 'Amount', 'Bucket', 'Age (days)', 'Status']
          rows = data.items.map(r => ({ 'Invoice #': r.invoiceNumber, Customer: r.customerName, 'Due Date': r.dueDate, Amount: formatCurrency(r.totalAmount), Bucket: r.bucket, 'Age (days)': r.ageDays, Status: r.status }))
          break
        }
        case 'department-budget': {
          const res = await reportsService.getDepartmentBudget()
          const data = res.data as { items: Array<{ code: string; name: string; budget: number; actual: number; remaining: number; utilizationPct: number }>; totalBudget: number; totalActual: number }
          columns = ['Code', 'Department', 'Budget', 'Actual', 'Remaining', 'Utilization %']
          rows = data.items.map(r => ({ Code: r.code, Department: r.name, Budget: formatCurrency(r.budget), Actual: formatCurrency(r.actual), Remaining: formatCurrency(r.remaining), 'Utilization %': `${r.utilizationPct}%` }))
          summary = { 'Total Budget': data.totalBudget, 'Total Actual': data.totalActual }
          break
        }
      }

      setRrResult({ rows, columns, summary })
      push('success', `${REPORT_LABELS[rrType]} loaded successfully.`)
    } catch {
      push('error', `Failed to load ${REPORT_LABELS[rrType]}.`)
    } finally {
      setRrLoading(false)
    }
  }, [rrType, rrStartDate, rrEndDate, rrAsOfDate, push])

  // ── Export ──────────────────────────────────────────────────────────────────

  const handleExport = async () => {
    setExpLoading(true)
    try {
      const params: Record<string, string> = expIsDateRange
        ? { startDate: expStartDate, endDate: expEndDate }
        : { asOfDate: expAsOfDate }
      const res = await reportsService.exportReport(expType, expFormat, params)
      const blob = res.data as Blob
      const ext = expFormat === 'excel' ? 'xlsx' : 'pdf'
      const url = URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = `${expType}-${today}.${ext}`
      link.click()
      URL.revokeObjectURL(url)
      push('success', `Downloaded: ${expType}.${ext}`)
      setShowExport(false)
    } catch {
      push('error', 'Export failed. Please try again.')
    } finally {
      setExpLoading(false)
    }
  }

  // ── Drill-down ──────────────────────────────────────────────────────────────

  const handleLoadDrilldown = async () => {
    setDdLoading(true)
    setDdRows([])
    setDdColumns([])
    setDdSummary([])
    try {
      if (ddType === 'aging-ap') {
        const res = await reportsService.getAgingAp({ asOfDate: ddAsOfDate })
        const data = res.data as {
          items: Array<{ invoiceNumber: string; vendorName: string; dueDate: string; totalAmount: number; bucket: string; ageDays: number; status: string }>
          summary: Array<{ bucket: string; total: number }>
        }
        setDdColumns(['Invoice #', 'Vendor', 'Due Date', 'Amount', 'Bucket', 'Age (days)', 'Status'])
        setDdRows(data.items.map(r => ({ 'Invoice #': r.invoiceNumber, Vendor: r.vendorName, 'Due Date': r.dueDate, Amount: formatCurrency(r.totalAmount), Bucket: r.bucket, 'Age (days)': r.ageDays, Status: r.status })))
        setDdSummary(data.summary)
      } else if (ddType === 'aging-ar') {
        const res = await reportsService.getAgingAr({ asOfDate: ddAsOfDate })
        const data = res.data as {
          items: Array<{ invoiceNumber: string; customerName: string; dueDate: string; totalAmount: number; bucket: string; ageDays: number; status: string }>
          summary: Array<{ bucket: string; total: number }>
        }
        setDdColumns(['Invoice #', 'Customer', 'Due Date', 'Amount', 'Bucket', 'Age (days)', 'Status'])
        setDdRows(data.items.map(r => ({ 'Invoice #': r.invoiceNumber, Customer: r.customerName, 'Due Date': r.dueDate, Amount: formatCurrency(r.totalAmount), Bucket: r.bucket, 'Age (days)': r.ageDays, Status: r.status })))
        setDdSummary(data.summary)
      } else {
        const res = await reportsService.getDepartmentBudget()
        const data = res.data as { items: Array<{ code: string; name: string; budget: number; actual: number; remaining: number; utilizationPct: number }> }
        setDdColumns(['Code', 'Department', 'Budget', 'Actual', 'Remaining', 'Utilization %'])
        setDdRows(data.items.map(r => ({ Code: r.code, Department: r.name, Budget: formatCurrency(r.budget), Actual: formatCurrency(r.actual), Remaining: formatCurrency(r.remaining), 'Utilization %': `${r.utilizationPct}%` })))
      }
      push('success', 'Drill-down data loaded.')
    } catch {
      push('error', 'Failed to load drill-down data.')
    } finally {
      setDdLoading(false)
    }
  }

  const loadTemplates = useCallback(async () => {
    setTemplatesLoading(true)
    try {
      const res = await reportsService.listTemplates()
      const items = (res.data.items ?? []).map((item) => ({
        id: item.id,
        name: item.name,
        type: toReportType(item.type),
        visibility: item.visibility,
        updatedAt: item.updatedAt,
      }))
      setTemplates(items)
    } catch {
      push('error', 'Unable to load templates.')
    } finally {
      setTemplatesLoading(false)
    }
  }, [push])

  const handleAddTemplate = async () => {
    if (!templateName.trim()) {
      push('warning', 'Template name is required.')
      return
    }

    setTemplatesBusy(true)
    try {
      const res = await reportsService.createTemplate({
        name: templateName.trim(),
        type: templateType,
        visibility: templateVisibility,
      })

      setTemplates((prev) => [
        {
          id: res.data.id,
          name: res.data.name,
          type: toReportType(res.data.type),
          visibility: res.data.visibility,
          updatedAt: res.data.updatedAt,
        },
        ...prev,
      ])
      setTemplateName('')
      setTemplateType('income-statement')
      setTemplateVisibility('Private')
      push('success', 'Template saved.')
    } catch {
      push('error', 'Failed to save template.')
    } finally {
      setTemplatesBusy(false)
    }
  }

  const handleDeleteTemplate = async (id: string) => {
    setTemplatesBusy(true)
    try {
      await reportsService.deleteTemplate(id)
      setTemplates((prev) => prev.filter((t) => t.id !== id))
      push('info', 'Template removed.')
    } catch {
      push('error', 'Failed to remove template.')
    } finally {
      setTemplatesBusy(false)
    }
  }

  const handleLoadAuditLog = async () => {
    setAuditLoading(true)
    try {
      const res = await reportsService.getAuditActivities()
      const data = (res.data as { activities?: Array<{ id: string; action: string; user: string; entity: string; status: string; timestamp: string }> }).activities ?? []
      setAuditLogs(
        data.map((item) => ({
          id: item.id,
          action: item.action,
          user: item.user,
          entity: item.entity,
          status: item.status,
          timestamp: item.timestamp,
        })),
      )
    } catch {
      setAuditLogs([
        { id: 'fallback-1', action: 'Report Opened', user: user?.email ?? 'accountant@cmnetwork.com', entity: 'Reports Module', status: 'success', timestamp: new Date().toISOString() },
      ])
      push('warning', 'Loaded fallback audit data.')
    } finally {
      setAuditLoading(false)
    }
  }

  const loadSchedules = useCallback(async () => {
    setSchedulerLoading(true)
    try {
      const res = await reportsService.listSchedules()
      const items = (res.data.items ?? []).map((item) => ({
        id: item.id,
        label: item.label,
        type: toReportType(item.type),
        cadence: item.cadence,
        target: item.target,
        active: item.active,
        updatedAt: item.updatedAt,
      }))
      setSchedulerItems(items)
    } catch {
      push('error', 'Unable to load report schedules.')
    } finally {
      setSchedulerLoading(false)
    }
  }, [push])

  const toggleScheduler = async (id: string) => {
    const item = schedulerItems.find((s) => s.id === id)
    if (!item) {
      return
    }

    setSchedulerBusyId(id)
    try {
      const res = await reportsService.updateSchedule(id, {
        label: item.label,
        type: item.type,
        cadence: item.cadence,
        target: item.target,
        active: !item.active,
      })

      setSchedulerItems((prev) => prev.map((entry) => (entry.id === id
        ? {
            ...entry,
            active: res.data.active,
            updatedAt: res.data.updatedAt,
          }
        : entry)))
      push('success', `${item.label} is now ${res.data.active ? 'active' : 'inactive'}.`)
    } catch {
      push('error', 'Failed to update schedule status.')
    } finally {
      setSchedulerBusyId(null)
    }
  }

  const createSchedule = async () => {
    if (!newScheduleLabel.trim()) {
      push('warning', 'Schedule label is required.')
      return
    }

    setSchedulerCreateBusy(true)
    try {
      const res = await reportsService.createSchedule({
        label: newScheduleLabel.trim(),
        type: newScheduleType,
        cadence: newScheduleCadence,
        target: newScheduleTarget,
        active: newScheduleActive,
      })

      setSchedulerItems((prev) => [
        {
          id: res.data.id,
          label: res.data.label,
          type: toReportType(res.data.type),
          cadence: res.data.cadence,
          target: res.data.target,
          active: res.data.active,
          updatedAt: res.data.updatedAt,
        },
        ...prev,
      ])

      setNewScheduleLabel('')
      setNewScheduleType('income-statement')
      setNewScheduleCadence('Weekly')
      setNewScheduleTarget('Excel')
      setNewScheduleActive(true)
      push('success', 'Schedule created.')
    } catch {
      push('error', 'Failed to create schedule.')
    } finally {
      setSchedulerCreateBusy(false)
    }
  }

  const runScheduledNow = async (item: SchedulerItem) => {
    setSchedulerBusyId(item.id)
    try {
      await reportsService.runScheduleNow(item.id)
      push('success', `${item.label} scheduled run triggered.`)
    } catch {
      push('error', 'Failed to trigger scheduled run.')
    } finally {
      setSchedulerBusyId(null)
    }
  }

  const loadLiveSummary = useCallback(async () => {
    setLiveSummaryLoading(true)
    try {
      const [templatesRes, schedulesRes, incomeRes] = await Promise.all([
        reportsService.listTemplates(),
        reportsService.listSchedules(),
        reportsService.getIncomeStatement({ startDate: firstOfMonth, endDate: today }),
      ])

      const templatesCount = templatesRes.data.items?.length ?? 0
      const schedules = schedulesRes.data.items ?? []
      const activeSchedules = schedules.filter((item) => item.active).length
      const incomeData = incomeRes.data as { netIncome?: number }

      setLiveSummary({
        savedReports: templatesCount,
        activeSchedules,
        netIncome: incomeData.netIncome ?? 0,
        lastUpdated: new Date().toISOString(),
      })
    } catch {
      push('warning', 'Unable to refresh live report summary right now.')
    } finally {
      setLiveSummaryLoading(false)
    }
  }, [push])

  useEffect(() => {
    void loadLiveSummary()
  }, [loadLiveSummary])

  // ── Render ──────────────────────────────────────────────────────────────────

  return (
    <section style={{ padding: '20px 24px' }}>
      <div style={{ maxWidth: 1240, margin: '0 auto' }}>
      {/* Header */}
      <div style={{ marginBottom: 16, background: '#fff', border: '1px solid #d5dbe4', borderRadius: 12, padding: '22px 22px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', gap: 16, alignItems: 'flex-start', flexWrap: 'wrap' }}>
          <div>
            <h1 style={{ fontSize: 50, fontWeight: 700, color: '#1e3a8a', margin: 0, lineHeight: 1 }}>Reports</h1>
            <p style={{ color: '#6b7280', marginTop: 8, marginBottom: 14, maxWidth: 640 }}>
              Consolidated reporting workspace with read-only and drill-down outputs based on role permissions.
            </p>
          </div>
          <button
            type="button"
            onClick={() => { void loadLiveSummary() }}
            disabled={liveSummaryLoading}
            style={{ border: '1px solid #cbd5e1', background: '#fff', color: '#1d4ed8', borderRadius: 8, padding: '8px 14px', fontWeight: 600, cursor: liveSummaryLoading ? 'not-allowed' : 'pointer' }}
          >
            {liveSummaryLoading ? 'Refreshing...' : 'Refresh Live Data'}
          </button>
        </div>
      </div>

      {/* Stats row */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: 16, marginBottom: 14 }}>
        {[
          { label: 'Saved Reports', value: String(liveSummary.savedReports), sub: 'Templates available in your role scope', valueColor: '#111827' },
          { label: 'Scheduled Exports', value: String(liveSummary.activeSchedules), sub: 'Active automations ready to run', valueColor: '#111827' },
          { label: 'Net Income (MTD)', value: formatCurrency(liveSummary.netIncome), sub: liveSummary.lastUpdated ? `Live as of ${new Date(liveSummary.lastUpdated).toLocaleString()}` : 'Loading from live APIs', valueColor: liveSummary.netIncome >= 0 ? '#065f46' : '#b91c1c' },
        ].map(({ label, value, sub, valueColor }) => (
          <div key={label} style={{ background: '#fff', borderRadius: 12, border: '1px solid #d1d5db', padding: '14px 16px', minHeight: 132 }}>
            <div style={{ fontWeight: 700, color: '#111827', marginBottom: 10, fontSize: 16 }}>{label}</div>
            <div style={{ fontSize: 50, fontWeight: 700, color: valueColor, lineHeight: 1 }}>{value}</div>
            <div style={{ fontSize: 13, color: '#9ca3af', marginTop: 6 }}>{sub}</div>
          </div>
        ))}
      </div>

      {/* Module Actions */}
      <div>
        <div style={{ fontWeight: 700, fontSize: 16, color: '#111827', marginBottom: 20 }}>Module Actions</div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: 16 }}>
          <ActionCard
            icon={<IconRunReport />}
            title="Run Report"
            description="Execute selected report template."
            onClick={() => { setRrResult(null); setShowRunReport(true) }}
          />
          <ActionCard
            icon={<IconExport />}
            title="Export Data"
            description="Download report output as file."
            onClick={() => setShowExport(true)}
          />
          <ActionCard
            icon={<IconDrilldown />}
            title="Open Drill-down"
            description="Inspect detailed report slices."
            onClick={() => { setDdRows([]); setDdSummary([]); setShowDrilldown(true) }}
          />
          <ActionCard
            icon={<IconTemplates />}
            title="Manage Templates"
            description="Create and edit report structures."
            onClick={() => {
              setShowTemplateManager(true)
              void loadTemplates()
            }}
          />
          <ActionCard
            icon={<IconAuditLog />}
            title="Audit Log"
            description="Review report access history."
            onClick={() => {
              setShowAuditLog(true)
              void handleLoadAuditLog()
            }}
          />
          <ActionCard
            icon={<IconScheduler />}
            title="Report Scheduler"
            description="Automate report generation."
            onClick={() => {
              setShowScheduler(true)
              void loadSchedules()
            }}
          />
        </div>
      </div>
      </div>

      {/* ── Run Report Modal ─────────────────────────────────────────────────── */}
      {showRunReport && (
        <Dialog title="Run Report — Execute Report Template" onClose={() => setShowRunReport(false)}>
          <div style={{ padding: '16px 8px', minWidth: 760 }}>
            <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'flex-end', marginBottom: 20 }}>
              <div>
                <label htmlFor="rr-type" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>Report Template</label>
                <select
                  id="rr-type"
                  value={rrType}
                  onChange={(e) => { setRrType(e.target.value as ReportType); setRrResult(null) }}
                  className="k-input k-input-md"
                  style={{ height: 36, minWidth: 200 }}
                >
                  {(Object.keys(REPORT_LABELS) as ReportType[]).map((t) => (
                    <option key={t} value={t}>{REPORT_LABELS[t]}</option>
                  ))}
                </select>
              </div>
              {rrIsDateRange && (
                <>
                  <div>
                    <label htmlFor="rr-start" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>Start Date</label>
                    <input id="rr-start" type="date" value={rrStartDate} onChange={(e) => setRrStartDate(e.target.value)} className="k-input k-input-md" style={{ height: 36 }} />
                  </div>
                  <div>
                    <label htmlFor="rr-end" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>End Date</label>
                    <input id="rr-end" type="date" value={rrEndDate} onChange={(e) => setRrEndDate(e.target.value)} className="k-input k-input-md" style={{ height: 36 }} />
                  </div>
                </>
              )}
              {!rrIsDateRange && !rrIsBudget && (
                <div>
                  <label htmlFor="rr-asof" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>As of Date</label>
                  <input id="rr-asof" type="date" value={rrAsOfDate} onChange={(e) => setRrAsOfDate(e.target.value)} className="k-input k-input-md" style={{ height: 36 }} />
                </div>
              )}

              <button
                type="button"
                onClick={handleRunReport}
                disabled={rrLoading}
                style={{ background: '#1d4ed8', color: '#fff', border: 'none', borderRadius: 8, padding: '0 20px', height: 36, fontWeight: 600, cursor: rrLoading ? 'not-allowed' : 'pointer', opacity: rrLoading ? 0.7 : 1 }}
              >
                {rrLoading ? 'Running...' : 'Run Report'}
              </button>
            </div>

            {rrResult?.summary && (
              <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' }}>
                {Object.entries(rrResult.summary).map(([k, v]) => (
                  <div key={k} style={{ background: '#f0f9ff', borderRadius: 8, padding: '10px 16px', border: '1px solid #bae6fd' }}>
                    <div style={{ fontSize: 11, fontWeight: 600, color: '#0369a1' }}>{k}</div>
                    <div style={{ fontSize: 16, fontWeight: 700, color: '#0c4a6e' }}>{formatCurrency(v)}</div>
                  </div>
                ))}
              </div>
            )}

            {rrResult && rrResult.rows.length > 0 && <ResultTable columns={rrResult.columns} rows={rrResult.rows} />}
            {rrResult?.rows.length === 0 && !rrLoading && (
              <p style={{ color: '#9ca3af', textAlign: 'center', padding: '32px 0' }}>No data for the selected period.</p>
            )}
            {!rrResult && !rrLoading && (
              <p style={{ color: '#9ca3af', textAlign: 'center', padding: '32px 0' }}>Select a template and click Run Report.</p>
            )}
          </div>
          <DialogActionsBar>
            <button type="button" onClick={() => setShowRunReport(false)} style={{ padding: '6px 18px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Close
            </button>
          </DialogActionsBar>
        </Dialog>
      )}

      {/* ── Export Modal ─────────────────────────────────────────────────────── */}
      {showExport && (
        <Dialog title="Export Data — Download Report as File" onClose={() => setShowExport(false)}>
          <div style={{ padding: '16px 8px', minWidth: 460 }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div>
                <label htmlFor="exp-type" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Report Type</label>
                <select
                  id="exp-type"
                  value={expType}
                  onChange={(e) => setExpType(e.target.value as ReportType)}
                  className="k-input k-input-md"
                  style={{ height: 36, width: '100%' }}
                >
                  {EXPORTABLE_TYPES.map((t) => (
                    <option key={t} value={t}>{REPORT_LABELS[t]}</option>
                  ))}
                </select>
              </div>

              <div>
                <span style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Export Format</span>
                <div style={{ display: 'flex', gap: 20 }}>
                  {(['excel', 'pdf'] as const).map((fmt) => (
                    <label key={fmt} style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontWeight: expFormat === fmt ? 700 : 400 }}>
                      <input type="radio" name="expFormat" value={fmt} checked={expFormat === fmt} onChange={() => setExpFormat(fmt)} />
                      {fmt === 'excel' ? 'Excel (.xlsx)' : 'PDF (.pdf)'}
                    </label>
                  ))}
                </div>
              </div>

              {expIsDateRange ? (
                <div style={{ display: 'flex', gap: 12 }}>
                  <div style={{ flex: 1 }}>
                    <label htmlFor="exp-start" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>Start Date</label>
                    <input id="exp-start" type="date" value={expStartDate} onChange={(e) => setExpStartDate(e.target.value)} className="k-input k-input-md" style={{ height: 36, width: '100%' }} />
                  </div>
                  <div style={{ flex: 1 }}>
                    <label htmlFor="exp-end" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>End Date</label>
                    <input id="exp-end" type="date" value={expEndDate} onChange={(e) => setExpEndDate(e.target.value)} className="k-input k-input-md" style={{ height: 36, width: '100%' }} />
                  </div>
                </div>
              ) : (
                <div>
                  <label htmlFor="exp-asof" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>As of Date</label>
                  <input id="exp-asof" type="date" value={expAsOfDate} onChange={(e) => setExpAsOfDate(e.target.value)} className="k-input k-input-md" style={{ height: 36, width: '100%' }} />
                </div>
              )}
            </div>
          </div>
          <DialogActionsBar>
            <button type="button" onClick={() => setShowExport(false)} style={{ padding: '6px 16px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Cancel
            </button>
            <button
              type="button"
              onClick={handleExport}
              disabled={expLoading}
              style={{ padding: '6px 20px', borderRadius: 6, border: 'none', background: '#1d4ed8', color: '#fff', fontWeight: 600, cursor: expLoading ? 'not-allowed' : 'pointer', opacity: expLoading ? 0.7 : 1 }}
            >
              {expLoading ? 'Downloading...' : 'Download'}
            </button>
          </DialogActionsBar>
        </Dialog>
      )}

      {/* ── Drill-down Modal ──────────────────────────────────────────────────── */}
      {showDrilldown && (
        <Dialog title="Open Drill-down — Inspect Detailed Report Slices" onClose={() => setShowDrilldown(false)}>
          <div style={{ padding: '16px 8px', minWidth: 860 }}>
            <div style={{ display: 'flex', gap: 12, alignItems: 'flex-end', marginBottom: 20, flexWrap: 'wrap' }}>
              <div>
                <label htmlFor="dd-type" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>Report Slice</label>
                <select
                  id="dd-type"
                  value={ddType}
                  onChange={(e) => { setDdType(e.target.value as typeof ddType); setDdRows([]); setDdSummary([]) }}
                  className="k-input k-input-md"
                  style={{ height: 36, minWidth: 220 }}
                >
                  <option value="aging-ap">AP Aging — Invoice Detail</option>
                  <option value="aging-ar">AR Aging — Invoice Detail</option>
                  <option value="department-budget">Department Budget — Breakdown</option>
                </select>
              </div>
              {ddType !== 'department-budget' && (
                <div>
                  <label htmlFor="dd-asof" style={{ display: 'block', fontSize: 13, fontWeight: 600, marginBottom: 4 }}>As of Date</label>
                  <input id="dd-asof" type="date" value={ddAsOfDate} onChange={(e) => setDdAsOfDate(e.target.value)} className="k-input k-input-md" style={{ height: 36 }} />
                </div>
              )}
              <button
                type="button"
                onClick={handleLoadDrilldown}
                disabled={ddLoading}
                style={{ background: '#1d4ed8', color: '#fff', border: 'none', borderRadius: 8, padding: '0 20px', height: 36, fontWeight: 600, cursor: ddLoading ? 'not-allowed' : 'pointer', opacity: ddLoading ? 0.7 : 1 }}
              >
                {ddLoading ? 'Loading...' : 'Load Drill-down'}
              </button>
            </div>

            {ddSummary.length > 0 && (
              <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' }}>
                {ddSummary.map((s) => (
                  <div key={s.bucket} style={{ background: '#fefce8', border: '1px solid #fde68a', borderRadius: 8, padding: '8px 14px', minWidth: 110 }}>
                    <div style={{ fontSize: 11, fontWeight: 600, color: '#92400e' }}>{s.bucket}</div>
                    <div style={{ fontSize: 15, fontWeight: 700, color: '#78350f' }}>{formatCurrency(s.total)}</div>
                  </div>
                ))}
              </div>
            )}

            {ddRows.length > 0 && <ResultTable columns={ddColumns} rows={ddRows} />}
            {ddRows.length === 0 && !ddLoading && (
              <p style={{ color: '#9ca3af', textAlign: 'center', padding: '32px 0' }}>Select a report slice and click Load Drill-down.</p>
            )}
          </div>
          <DialogActionsBar>
            <button type="button" onClick={() => setShowDrilldown(false)} style={{ padding: '6px 18px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Close
            </button>
          </DialogActionsBar>
        </Dialog>
      )}

      {/* ── Template Management Modal ───────────────────────────────────────── */}
      {showTemplateManager && (
        <Dialog title="Template Management" onClose={() => setShowTemplateManager(false)}>
          <div style={{ padding: '12px 8px', minWidth: 760 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr auto', gap: 10, alignItems: 'end', marginBottom: 14 }}>
              <div>
                <label htmlFor="tpl-name" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Template Name</label>
                <input id="tpl-name" value={templateName} onChange={(e) => setTemplateName(e.target.value)} className="k-input k-input-md" style={{ height: 36, width: '100%' }} />
              </div>
              <div>
                <label htmlFor="tpl-type" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Type</label>
                <select id="tpl-type" value={templateType} onChange={(e) => setTemplateType(e.target.value as ReportType)} className="k-input k-input-md" style={{ height: 36, width: '100%' }}>
                  {(Object.keys(REPORT_LABELS) as ReportType[]).map((t) => (
                    <option key={t} value={t}>{REPORT_LABELS[t]}</option>
                  ))}
                </select>
              </div>
              <div>
                <label htmlFor="tpl-vis" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Visibility</label>
                <select id="tpl-vis" value={templateVisibility} onChange={(e) => setTemplateVisibility(e.target.value as 'Private' | 'Team')} className="k-input k-input-md" style={{ height: 36, width: '100%' }}>
                  <option value="Private">Private</option>
                  <option value="Team">Team</option>
                </select>
              </div>
              <button type="button" onClick={handleAddTemplate} style={{ height: 36, border: 'none', borderRadius: 8, background: '#1d4ed8', color: '#fff', padding: '0 16px', fontWeight: 600, cursor: 'pointer' }}>
                {templatesBusy ? 'Saving...' : 'Save'}
              </button>
            </div>

            <div style={{ border: '1px solid #e5e7eb', borderRadius: 8, overflow: 'hidden' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                <thead style={{ background: '#f8fafc' }}>
                  <tr>
                    <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Name</th>
                    <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Type</th>
                    <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Visibility</th>
                    <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Updated</th>
                    <th style={{ textAlign: 'right', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {templatesLoading && (
                    <tr>
                      <td colSpan={5} style={{ padding: '14px', textAlign: 'center', color: '#9ca3af' }}>Loading templates...</td>
                    </tr>
                  )}
                  {templates.map((tpl) => (
                    <tr key={tpl.id}>
                      <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{tpl.name}</td>
                      <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{REPORT_LABELS[tpl.type]}</td>
                      <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{tpl.visibility}</td>
                      <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{new Date(tpl.updatedAt).toLocaleString()}</td>
                      <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6', textAlign: 'right' }}>
                        <button type="button" disabled={templatesBusy} onClick={() => void handleDeleteTemplate(tpl.id)} style={{ border: '1px solid #e5e7eb', borderRadius: 6, background: '#fff', padding: '4px 10px', cursor: templatesBusy ? 'not-allowed' : 'pointer', opacity: templatesBusy ? 0.6 : 1 }}>
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                  {!templatesLoading && templates.length === 0 && (
                    <tr>
                      <td colSpan={5} style={{ padding: '14px', textAlign: 'center', color: '#9ca3af' }}>No templates yet.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
          <DialogActionsBar>
            <button type="button" onClick={() => setShowTemplateManager(false)} style={{ padding: '6px 18px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Close
            </button>
          </DialogActionsBar>
        </Dialog>
      )}

      {/* ── Audit Log Modal ─────────────────────────────────────────────────── */}
      {showAuditLog && (
        <Dialog title="Audit Log" onClose={() => setShowAuditLog(false)}>
          <div style={{ padding: '12px 8px', minWidth: 860 }}>
            {auditLoading && <p style={{ color: '#6b7280' }}>Loading audit activities...</p>}
            {!auditLoading && (
              <div style={{ border: '1px solid #e5e7eb', borderRadius: 8, overflow: 'hidden' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
                  <thead style={{ background: '#f8fafc' }}>
                    <tr>
                      <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Action</th>
                      <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>User</th>
                      <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Entity</th>
                      <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Status</th>
                      <th style={{ textAlign: 'left', padding: '8px 10px', borderBottom: '1px solid #e5e7eb' }}>Timestamp</th>
                    </tr>
                  </thead>
                  <tbody>
                    {auditLogs.map((log) => (
                      <tr key={log.id}>
                        <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{humanize(log.action)}</td>
                        <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{log.user}</td>
                        <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{humanize(log.entity)}</td>
                        <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{humanize(log.status)}</td>
                        <td style={{ padding: '8px 10px', borderBottom: '1px solid #f3f4f6' }}>{new Date(log.timestamp).toLocaleString()}</td>
                      </tr>
                    ))}
                    {auditLogs.length === 0 && (
                      <tr>
                        <td colSpan={5} style={{ padding: '14px', textAlign: 'center', color: '#9ca3af' }}>No audit activities found.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            )}
          </div>
          <DialogActionsBar>
            <button type="button" onClick={() => void handleLoadAuditLog()} style={{ padding: '6px 14px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Refresh
            </button>
            <button type="button" onClick={() => setShowAuditLog(false)} style={{ padding: '6px 18px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Close
            </button>
          </DialogActionsBar>
        </Dialog>
      )}

      {/* ── Report Scheduler Modal ──────────────────────────────────────────── */}
      {showScheduler && (
        <Dialog title="Report Scheduler" onClose={() => setShowScheduler(false)}>
          <div style={{ padding: '12px 8px', minWidth: 760 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1fr auto', gap: 10, alignItems: 'end', marginBottom: 14 }}>
              <div>
                <label htmlFor="sch-label" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Schedule Label</label>
                <input id="sch-label" value={newScheduleLabel} onChange={(e) => setNewScheduleLabel(e.target.value)} className="k-input k-input-md" style={{ height: 36, width: '100%' }} />
              </div>
              <div>
                <label htmlFor="sch-type" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Type</label>
                <select id="sch-type" value={newScheduleType} onChange={(e) => setNewScheduleType(e.target.value as ReportType)} className="k-input k-input-md" style={{ height: 36, width: '100%' }}>
                  {(Object.keys(REPORT_LABELS) as ReportType[]).map((t) => (
                    <option key={t} value={t}>{REPORT_LABELS[t]}</option>
                  ))}
                </select>
              </div>
              <div>
                <label htmlFor="sch-cadence" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Cadence</label>
                <select id="sch-cadence" value={newScheduleCadence} onChange={(e) => setNewScheduleCadence(e.target.value as ScheduleCadence)} className="k-input k-input-md" style={{ height: 36, width: '100%' }}>
                  <option value="Daily">Daily</option>
                  <option value="Weekly">Weekly</option>
                  <option value="Monthly">Monthly</option>
                </select>
              </div>
              <div>
                <label htmlFor="sch-target" style={{ display: 'block', fontSize: 12, fontWeight: 600, marginBottom: 4 }}>Target</label>
                <select id="sch-target" value={newScheduleTarget} onChange={(e) => setNewScheduleTarget(e.target.value as ScheduleTarget)} className="k-input k-input-md" style={{ height: 36, width: '100%' }}>
                  <option value="Excel">Excel</option>
                  <option value="PDF">PDF</option>
                </select>
              </div>
              <button type="button" disabled={schedulerCreateBusy} onClick={() => void createSchedule()} style={{ height: 36, border: 'none', borderRadius: 8, background: '#1d4ed8', color: '#fff', padding: '0 16px', fontWeight: 600, cursor: schedulerCreateBusy ? 'not-allowed' : 'pointer', opacity: schedulerCreateBusy ? 0.7 : 1 }}>
                {schedulerCreateBusy ? 'Saving...' : 'Add'}
              </button>
            </div>

            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 6, marginBottom: 12, fontSize: 12, color: '#4b5563' }}>
              <input type="checkbox" checked={newScheduleActive} onChange={(e) => setNewScheduleActive(e.target.checked)} />
              <span>Active on create</span>
            </label>

            <div style={{ display: 'grid', gap: 10 }}>
              {schedulerLoading && (
                <div style={{ border: '1px solid #e5e7eb', borderRadius: 8, padding: '12px', color: '#9ca3af', textAlign: 'center' }}>Loading schedules...</div>
              )}
              {schedulerItems.map((item) => (
                <div key={item.id} style={{ border: '1px solid #e5e7eb', borderRadius: 8, padding: '10px 12px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 10 }}>
                  <div>
                    <div style={{ fontWeight: 700, color: '#111827' }}>{item.label}</div>
                    <div style={{ fontSize: 12, color: '#6b7280' }}>
                      {REPORT_LABELS[item.type]} • {item.cadence} • {item.target}
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button type="button" disabled={schedulerBusyId === item.id} onClick={() => void toggleScheduler(item.id)} style={{ border: '1px solid #d1d5db', borderRadius: 6, background: item.active ? '#ecfdf5' : '#fff', color: item.active ? '#047857' : '#111827', padding: '5px 10px', cursor: schedulerBusyId === item.id ? 'not-allowed' : 'pointer', fontWeight: 600, opacity: schedulerBusyId === item.id ? 0.7 : 1 }}>
                      {item.active ? 'Active' : 'Inactive'}
                    </button>
                    <button type="button" disabled={schedulerBusyId === item.id} onClick={() => void runScheduledNow(item)} style={{ border: 'none', borderRadius: 6, background: '#1d4ed8', color: '#fff', padding: '5px 10px', cursor: schedulerBusyId === item.id ? 'not-allowed' : 'pointer', fontWeight: 600, opacity: schedulerBusyId === item.id ? 0.7 : 1 }}>
                      Run Now
                    </button>
                  </div>
                </div>
              ))}
              {!schedulerLoading && schedulerItems.length === 0 && (
                <div style={{ border: '1px solid #e5e7eb', borderRadius: 8, padding: '12px', color: '#9ca3af', textAlign: 'center' }}>No schedules yet.</div>
              )}
            </div>
          </div>
          <DialogActionsBar>
            <button type="button" onClick={() => setShowScheduler(false)} style={{ padding: '6px 18px', borderRadius: 6, border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer', fontWeight: 600 }}>
              Close
            </button>
          </DialogActionsBar>
        </Dialog>
      )}
    </section>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { Button } from '@progress/kendo-react-buttons'
import { apiClient } from '../../services/apiClient'
import { useAuthStore } from '../../store/authStore'
import { useNotificationStore } from '../../store/notificationStore'
import { extractApiError } from '../../utils/errorUtils'
import { MyPayslipsPage } from './payroll/MyPayslipsPage'
import { PayrollApprovalPage } from './payroll/PayrollApprovalPage'
import { payrollFaqItems, payrollWalkthroughSteps } from './payroll/helpContent'
import type { PayrollHelpRole } from './payroll/helpContent'
import { PayrollOverviewPage } from './payroll/PayrollOverviewPage'
import { PayrollProcessingPage } from './payroll/PayrollProcessingPage'
import { PayPeriodManagementPage } from './payroll/PayPeriodManagementPage'
import type {
  EmployeePayrollDto,
  PayPeriodDto,
  PayrollLineInput,
  PayrollIntegrationCapabilitiesDto,
  PayrollRegisterDto,
  PayrollRunDto,
  PayslipSummaryDto,
} from './payroll/types'

export const PayrollOperationsModule = () => {
  const selectedRole = useAuthStore((state) => state.selectedRole)
  const pushToast = useNotificationStore((state) => state.push)
  const isAccountant = selectedRole === 'accountant' || selectedRole === 'super-admin'
  const isCfo = selectedRole === 'cfo' || selectedRole === 'super-admin'
  const isEmployee = selectedRole === 'employee' || selectedRole === 'super-admin'

  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [helpOpen, setHelpOpen] = useState(false)
  const [walkthroughOpen, setWalkthroughOpen] = useState(false)
  const [helpQuery, setHelpQuery] = useState('')

  const [activePage, setActivePage] = useState<'overview' | 'periods' | 'processing' | 'approval' | 'payslips'>('overview')
  const [periods, setPeriods] = useState<PayPeriodDto[]>([])
  const [runs, setRuns] = useState<PayrollRunDto[]>([])
  const [selectedPeriodId, setSelectedPeriodId] = useState('')
  const [employees, setEmployees] = useState<EmployeePayrollDto[]>([])
  const [lines, setLines] = useState<PayrollLineInput[]>([])
  const [run, setRun] = useState<PayrollRunDto | null>(null)
  const [capabilities, setCapabilities] = useState<PayrollIntegrationCapabilitiesDto | null>(null)

  const [registerRunId, setRegisterRunId] = useState('')
  const [register, setRegister] = useState<PayrollRegisterDto | null>(null)
  const [myPayslips, setMyPayslips] = useState<PayslipSummaryDto[]>([])

  const [createPeriod, setCreatePeriod] = useState({
    year: new Date().getFullYear(),
    month: new Date().getMonth() + 1,
    frequency: 1,
    cutoffDate: '',
    payDate: '',
  })

  const loadPeriods = async () => {
    try {
      const response = await apiClient.get<PayPeriodDto[]>('/payroll/pay-periods')
      setPeriods(response.data)
    } catch (error) {
      const message = extractApiError(error, 'Unable to load pay periods.')
      setError(message)
      pushToast('error', message)
    }
  }

  const loadRuns = async () => {
    try {
      const response = await apiClient.get<PayrollRunDto[]>('/payroll/runs')
      setRuns(response.data)
    } catch (error) {
      const message = extractApiError(error, 'Unable to load payroll runs.')
      setError(message)
      pushToast('error', message)
    }
  }

  const loadCapabilities = async () => {
    if (!isAccountant && !isCfo) return

    try {
      const response = await apiClient.get<PayrollIntegrationCapabilitiesDto>('/payroll/integration-capabilities')
      setCapabilities(response.data)
    } catch (error) {
      const message = extractApiError(error, 'Unable to load payroll integration capabilities.')
      setError(message)
      pushToast('error', message)
    }
  }

  const loadMyPayslips = async () => {
    if (!isEmployee) return
    try {
      const response = await apiClient.get<PayslipSummaryDto[]>('/payroll/payslips/my-payslips')
      setMyPayslips(response.data)
    } catch (error) {
      const message = extractApiError(error, 'Unable to load payslips.')
      setError(message)
      pushToast('error', message)
    }
  }

  useEffect(() => {
    void loadPeriods()
    void loadRuns()
    void loadMyPayslips()
    void loadCapabilities()
  }, [])

  const periodOptions = useMemo(
    () => periods.map((period) => ({
      id: period.id,
      label: `${period.year}-${String(period.month).padStart(2, '0')}`,
    })),
    [periods],
  )

  const loadSetup = async () => {
    if (!selectedPeriodId) return

    setLoading(true)
    setError('')
    try {
      const response = await apiClient.get<{ payPeriodId: string; employees: EmployeePayrollDto[] }>(
        `/payroll/runs/${selectedPeriodId}/setup`,
      )
      const employeesData = response.data.employees
      setEmployees(employeesData)
      setLines(
        employeesData.map((employee) => ({
          employeeId: employee.id,
          employeeName: employee.name,
          regularHours: 0,
          overtimeHours: 0,
          absenceHours: 0,
          otherDeductions: 0,
        })),
      )
    } catch (error) {
      const message = extractApiError(error, 'Unable to load payroll setup for selected period.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onCreatePeriod = async () => {
    setLoading(true)
    setError('')
    try {
      await apiClient.post('/payroll/pay-periods', createPeriod)
      await loadPeriods()
      await loadRuns()
      pushToast('success', 'Pay period created successfully.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to create pay period.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onCalculate = async () => {
    if (!selectedPeriodId) {
      setError('Select a pay period first.')
      return
    }

    setLoading(true)
    setError('')
    try {
      const response = await apiClient.post<PayrollRunDto>(`/payroll/runs/${selectedPeriodId}/calculate`, {
        lineItems: lines,
      })
      setRun(response.data)
      setRegisterRunId(response.data.id)
      await loadRuns()
      pushToast('success', 'Payroll calculated. Review totals before submitting.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to calculate payroll.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onSubmit = async () => {
    if (!run) {
      setError('Calculate payroll first.')
      return
    }

    setLoading(true)
    setError('')
    try {
      const response = await apiClient.post<PayrollRunDto>(`/payroll/runs/${run.id}/submit`)
      setRun(response.data)
      setRegisterRunId(response.data.id)
      await loadRuns()
      pushToast('success', 'Payroll submitted. CFO can now approve or reject this run.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to submit payroll.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onWithdraw = async () => {
    if (!run) {
      setError('No payroll run available.')
      return
    }

    const note = globalThis.prompt('Optional: reason for withdrawal', 'Correcting hours and deductions')
    if (note === null) return

    setLoading(true)
    setError('')
    try {
      const response = await apiClient.post<PayrollRunDto>(`/payroll/runs/${run.id}/withdraw`, {
        withdrawalReason: note,
      })
      setRun(response.data)
      await loadRuns()
      pushToast('warning', 'Payroll withdrawn to Draft for correction.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to withdraw payroll.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onPostToGl = async () => {
    if (!run) {
      setError('No payroll run available.')
      return
    }

    setLoading(true)
    setError('')
    try {
      const response = await apiClient.post<PayrollRunDto>(`/payroll/runs/${run.id}/post-to-gl`)
      setRun(response.data)
      await loadRuns()
      pushToast('success', 'Payroll posted to GL successfully.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to post payroll to GL.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const loadRegister = async () => {
    if (!registerRunId) return

    setLoading(true)
    setError('')
    try {
      const response = await apiClient.get<PayrollRegisterDto>(`/payroll/runs/${registerRunId}/register`)
      setRegister(response.data)
    } catch (error) {
      const message = extractApiError(error, 'Unable to load payroll register.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onApprove = async () => {
    if (!registerRunId) return
    setLoading(true)
    setError('')
    try {
      await apiClient.post(`/payroll/runs/${registerRunId}/approve`, { approverNotes: '' })
      await loadRuns()
      await loadMyPayslips()
      await loadRegister()
      pushToast('success', 'Payroll approved. Payslips were generated for included employees.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to approve payroll.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onReject = async () => {
    if (!registerRunId) return
    const reason = globalThis.prompt('Enter rejection reason')
    if (!reason) return

    setLoading(true)
    setError('')
    try {
      await apiClient.post(`/payroll/runs/${registerRunId}/reject`, { rejectionReason: reason })
      await loadRuns()
      await loadRegister()
      pushToast('warning', 'Payroll rejected and returned for correction.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to reject payroll.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const onReopen = async () => {
    if (!registerRunId) return

    const reason = globalThis.prompt('Re-open reason (required):')
    if (!reason?.trim()) {
      setError('Re-open reason is required.')
      return
    }

    setLoading(true)
    setError('')
    try {
      await apiClient.post(`/payroll/runs/${registerRunId}/re-open`, { reopenReason: reason.trim() })
      await loadRuns()
      await loadRegister()
      pushToast('warning', 'Payroll re-opened and moved back to Draft.')
    } catch (error) {
      const message = extractApiError(error, 'Unable to re-open payroll.')
      setError(message)
      pushToast('error', message)
    } finally {
      setLoading(false)
    }
  }

  const updateLine = (employeeId: string, field: keyof PayrollLineInput, value: number) => {
    setLines((current) =>
      current.map((line) =>
        line.employeeId === employeeId
          ? {
              ...line,
              [field]: Number.isFinite(value) ? value : 0,
            }
          : line,
      ),
    )
  }

  const onCreatePeriodChange = (field: keyof typeof createPeriod, value: number | string) => {
    setCreatePeriod((current) => ({ ...current, [field]: value }))
  }

  const pageButtons = [
    { key: 'overview', label: 'Overview', visible: true },
    { key: 'periods', label: 'Pay Periods', visible: isAccountant },
    { key: 'processing', label: 'Processing', visible: isAccountant },
    { key: 'approval', label: 'Approval', visible: isCfo },
    { key: 'payslips', label: 'My Payslips', visible: isEmployee },
  ] as const

  const roleForHelp: PayrollHelpRole =
    selectedRole === 'accountant'
    || selectedRole === 'cfo'
    || selectedRole === 'employee'
    || selectedRole === 'super-admin'
      ? selectedRole
      : 'employee'
  const reopenGuidance = selectedRole === 'cfo'
    ? 'CFO re-open is allowed only within 24 hours after approval and before posting/payment.'
    : 'SuperAdmin can re-open approved/processed runs before posting/payment. All changes are audited.'
  const contextualFaqs = useMemo(() => {
    const query = helpQuery.trim().toLowerCase()
    return payrollFaqItems.filter((item) => {
      const matchesRole = item.roles.includes(roleForHelp)
      const matchesPage = item.pages.includes(activePage)
      const matchesQuery = query.length === 0
        || item.question.toLowerCase().includes(query)
        || item.answer.toLowerCase().includes(query)
      return matchesRole && matchesPage && matchesQuery
    })
  }, [activePage, helpQuery, roleForHelp])

  return (
    <section className="page-fade-in">
      <article className="card" style={{ marginBottom: '1rem' }}>
        <header className="card-head">
          <h2 className="card-title">Payroll Operations</h2>
          <p className="card-subtitle">Five dedicated pages backed by live payroll records</p>
        </header>

        {error && (
          <p style={{ color: '#9b1c1c', background: '#fee2e2', padding: '0.65rem', borderRadius: '0.5rem' }}>
            {error}
          </p>
        )}

        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
          {pageButtons.filter((button) => button.visible).map((button) => (
            <Button
              key={button.key}
              onClick={() => setActivePage(button.key)}
              fillMode={activePage === button.key ? 'solid' : 'outline'}
            >
              {button.label}
            </Button>
          ))}

          <Button fillMode="outline" onClick={() => setWalkthroughOpen(true)}>
            Payroll Walkthrough
          </Button>
          <Button fillMode="outline" onClick={() => setHelpOpen((current) => !current)}>
            Need Help?
          </Button>
        </div>

        {helpOpen && (
          <section style={{ marginTop: '0.9rem', border: '1px solid #d1d5db', borderRadius: '0.6rem', padding: '0.8rem' }}>
            <div style={{ display: 'flex', gap: '0.6rem', alignItems: 'center', marginBottom: '0.6rem' }}>
              <strong>Help for {activePage}</strong>
              <input
                type="search"
                placeholder="Search help"
                value={helpQuery}
                onChange={(e) => setHelpQuery(e.target.value)}
                style={{ flex: 1 }}
              />
            </div>

            {contextualFaqs.length === 0 ? (
              <p className="card-subtitle" style={{ margin: 0 }}>
                No matching help topics. Try a different keyword or open Payroll Walkthrough.
              </p>
            ) : (
              <div style={{ display: 'grid', gap: '0.6rem' }}>
                {contextualFaqs.map((item) => (
                  <article key={item.id} style={{ border: '1px solid #e5e7eb', borderRadius: '0.5rem', padding: '0.6rem' }}>
                    <p style={{ margin: 0, fontWeight: 600 }}>{item.question}</p>
                    <p className="card-subtitle" style={{ marginBottom: 0 }}>{item.answer}</p>
                  </article>
                ))}
              </div>
            )}
          </section>
        )}
      </article>

      {walkthroughOpen && (
        <section style={{
          position: 'fixed',
          inset: 0,
          background: 'rgba(15, 23, 42, 0.55)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 50,
          padding: '1rem',
        }}>
          <article className="card" style={{ width: 'min(860px, 100%)', maxHeight: '85vh', overflowY: 'auto' }}>
            <header className="card-head">
              <h3 className="card-title">Payroll Walkthrough</h3>
              <p className="card-subtitle">Replay this guide anytime from the Payroll page.</p>
            </header>
            <div style={{ display: 'grid', gap: '0.6rem' }}>
              {payrollWalkthroughSteps.map((step) => (
                <article key={step.title} style={{ border: '1px solid #e5e7eb', borderRadius: '0.5rem', padding: '0.65rem' }}>
                  <p style={{ margin: 0, fontWeight: 600 }}>{step.title}</p>
                  <p className="card-subtitle" style={{ marginBottom: 0 }}>{step.detail}</p>
                </article>
              ))}
            </div>
            <div style={{ marginTop: '0.8rem', display: 'flex', justifyContent: 'flex-end', gap: '0.5rem' }}>
              <Button fillMode="outline" onClick={() => setWalkthroughOpen(false)}>Close</Button>
            </div>
          </article>
        </section>
      )}

      {activePage === 'overview' && (
        <PayrollOverviewPage periods={periods} runs={runs} capabilities={capabilities} />
      )}

      {activePage === 'periods' && isAccountant && (
        <PayPeriodManagementPage
          periods={periods}
          createPeriod={createPeriod}
          loading={loading}
          onCreatePeriodChange={onCreatePeriodChange}
          onCreatePeriod={onCreatePeriod}
          onSelectPeriod={setSelectedPeriodId}
          selectedPeriodId={selectedPeriodId}
        />
      )}

      {activePage === 'processing' && isAccountant && (
        <PayrollProcessingPage
          loading={loading}
          selectedPeriodId={selectedPeriodId}
          periodOptions={periodOptions}
          employees={employees}
          lines={lines}
          run={run}
          onSelectPeriod={setSelectedPeriodId}
          onLoadSetup={loadSetup}
          onUpdateLine={updateLine}
          onCalculate={onCalculate}
          onSubmit={onSubmit}
          onWithdraw={onWithdraw}
          onPostToGl={onPostToGl}
          canWithdraw={isAccountant}
        />
      )}

      {activePage === 'approval' && isCfo && (
        <PayrollApprovalPage
          loading={loading}
          runs={runs}
          selectedRunId={registerRunId}
          register={register}
          onSelectRun={setRegisterRunId}
          onLoadRegister={loadRegister}
          onApprove={onApprove}
          onReject={onReject}
          onReopen={onReopen}
          reopenGuidance={reopenGuidance}
        />
      )}

      {activePage === 'payslips' && isEmployee && (
        <MyPayslipsPage
          payslips={myPayslips}
          loading={loading}
          onRefresh={loadMyPayslips}
        />
      )}
    </section>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { useLocation } from 'react-router-dom'
import { Button } from '@progress/kendo-react-buttons'
import { Dialog, DialogActionsBar } from '@progress/kendo-react-dialogs'
import { Input, type InputChangeEvent } from '@progress/kendo-react-inputs'
import { Badge } from '@progress/kendo-react-indicators'
import { DashboardCard } from '../../components/DashboardCard'
import {
  adminService,
  type BackupRecord,
  type IntegrationSetting,
  type SecurityPolicy,
} from '../../services/adminService'
import { auditLogsService } from '../../services/extendedOperationsService'
import { useAuthStore } from '../../store/authStore'
import { useNotificationStore } from '../../store/notificationStore'

type SettingsView = 'overview' | 'security' | 'backup' | 'integrations' | 'audit'

const viewByHash: Record<string, SettingsView> = {
  '#security-policy': 'security',
  '#backup-restore': 'backup',
  '#integrations': 'integrations',
  '#audit-logs': 'audit',
}

const viewTitle: Record<SettingsView, string> = {
  overview: 'System Settings',
  security: 'System Settings / Security Policy',
  backup: 'System Settings / Backup & Restore',
  integrations: 'System Settings / Integrations',
  audit: 'System Settings / Audit Logs',
}

const isPasswordPolicy = (policy: SecurityPolicy) => {
  const text = `${policy.name} ${policy.description}`.toLowerCase()
  return text.includes('password') || text.includes('mfa') || text.includes('login')
}

// Convert camelCase / snake_case / kebab-case keys into a friendly label.
const humanizeKey = (key: string): string => {
  const spaced = key
    .replaceAll(/[_-]+/g, ' ')
    .replaceAll(/([a-z0-9])([A-Z])/g, '$1 $2')
    .replaceAll(/\s+/g, ' ')
    .trim()
  if (!spaced) return key
  return spaced.charAt(0).toUpperCase() + spaced.slice(1)
}

const formatLeafValue = (value: unknown): React.ReactNode => {
  if (value === null || value === undefined) {
    return <span className="settings-policy-pill settings-policy-pill-muted">—</span>
  }
  if (typeof value === 'boolean') {
    return (
      <span
        className={`settings-policy-pill ${value ? 'settings-policy-pill-on' : 'settings-policy-pill-off'}`}
      >
        {value ? 'Enabled' : 'Disabled'}
      </span>
    )
  }
  if (typeof value === 'number') {
    return <span className="settings-policy-pill settings-policy-pill-num">{value.toLocaleString()}</span>
  }
  if (typeof value === 'string') {
    return value.trim().length === 0
      ? <span className="settings-policy-pill settings-policy-pill-muted">empty</span>
      : <span className="settings-policy-pill">{value}</span>
  }
  if (Array.isArray(value)) {
    if (value.length === 0) {
      return <span className="settings-policy-pill settings-policy-pill-muted">none</span>
    }
    return (
      <span className="settings-policy-pill-group">
        {value.map((item, i) => {
          const text = String(item)
          return (
            <span key={`${i}-${text}`} className="settings-policy-pill">{text}</span>
          )
        })}
      </span>
    )
  }
  return <span className="settings-policy-pill">{JSON.stringify(value)}</span>
}

const renderPolicyFields = (obj: Record<string, unknown>): React.ReactNode => (
  <div className="settings-policy-fields">
    {Object.entries(obj).map(([k, v]) => (
      <div className="settings-policy-field" key={k}>
        <span className="settings-policy-field-key">{humanizeKey(k)}</span>
        <span className="settings-policy-field-val">{formatLeafValue(v)}</span>
      </div>
    ))}
  </div>
)

const renderPolicyValue = (rawValue: string): React.ReactNode => {
  if (!rawValue?.trim()) return null
  const trimmed = rawValue.trim()
  // Only attempt JSON parsing for object / array literals.
  if (!(trimmed.startsWith('{') || trimmed.startsWith('['))) {
    return <p className="settings-policy-value">{rawValue}</p>
  }

  let parsed: unknown
  try {
    parsed = JSON.parse(trimmed)
  } catch {
    return <p className="settings-policy-value">{rawValue}</p>
  }

  if (parsed === null || typeof parsed !== 'object') {
    const primitive = parsed as string | number | boolean | null
    return <p className="settings-policy-value">{primitive === null ? '' : String(primitive)}</p>
  }

  if (Array.isArray(parsed)) {
    return (
      <div className="settings-policy-tree">
        <div className="settings-policy-section">
          <div className="settings-policy-section-title">Items</div>
          {renderPolicyFields(Object.fromEntries(parsed.map((v, i) => [String(i + 1), v])))}
        </div>
      </div>
    )
  }

  const obj = parsed as Record<string, unknown>
  const sectionEntries = Object.entries(obj)
  const allSectionsAreObjects = sectionEntries.every(
    ([, v]) => v !== null && typeof v === 'object' && !Array.isArray(v),
  )

  if (allSectionsAreObjects && sectionEntries.length > 0) {
    return (
      <div className="settings-policy-tree">
        {sectionEntries.map(([sectionKey, sectionVal]) => (
          <div className="settings-policy-section" key={sectionKey}>
            <div className="settings-policy-section-title">{humanizeKey(sectionKey)}</div>
            {renderPolicyFields(sectionVal as Record<string, unknown>)}
          </div>
        ))}
      </div>
    )
  }

  // Flat object — render as one field grid.
  return (
    <div className="settings-policy-tree">
      <div className="settings-policy-section">{renderPolicyFields(obj)}</div>
    </div>
  )
}

const isSessionPolicy = (policy: SecurityPolicy) => {
  const text = `${policy.name} ${policy.description}`.toLowerCase()
  return text.includes('session') || text.includes('timeout')
}

const getIntegrationThemeColor = (status: IntegrationSetting['status']) => {
  if (status === 'active') {
    return 'success'
  }

  if (status === 'error') {
    return 'error'
  }

  return 'warning'
}

interface AuditLogItem {
  id: string
  date: string
  rawDate: string
  user: string
  area: string
  action: string
  reviewed: boolean
  details?: string | null
}

interface AuditChange {
  field: string
  before: string
  after: string
}

const humanize = (value: string | null | undefined): string => {
  if (!value) return ''
  return value
    .replaceAll(/([a-z0-9])([A-Z])/g, '$1 $2')
    .replaceAll(/([A-Z]+)([A-Z][a-z])/g, '$1 $2')
    .replaceAll(/[_-]+/g, ' ')
    .trim()
}

const FRIENDLY_ACTIONS: Record<string, string> = {
  GET: 'Viewed',
  POST: 'Submitted',
  PUT: 'Updated',
  PATCH: 'Updated',
  DELETE: 'Deleted',
  LoginSucceeded: 'Sign-In Succeeded',
  LoginFailed: 'Sign-In Failed',
  Logout: 'Signed Out',
  Reviewed: 'Marked Reviewed',
  Exported: 'Exported',
}

const AREA_BY_PATH: Array<{ test: RegExp; label: string }> = [
  { test: /\/auth\/login/i, label: 'Sign-In' },
  { test: /\/auth\//i, label: 'Authentication' },
  { test: /\/admin\/users/i, label: 'User Management' },
  { test: /\/admin\/security-policies/i, label: 'Security Policy' },
  { test: /\/admin\/backups/i, label: 'Backup & Restore' },
  { test: /\/admin\/integrations/i, label: 'Integrations' },
  { test: /\/admin\/audit-logs/i, label: 'Audit Logs' },
  { test: /\/auditor\/evidence-archives/i, label: 'Evidence Archive' },
  { test: /\/general-ledger/i, label: 'General Ledger' },
  { test: /\/reports\//i, label: 'Reports' },
  { test: /\/vendors/i, label: 'Vendor Master' },
  { test: /\/customers/i, label: 'Customer Master' },
]

const FRIENDLY_ENTITY: Record<string, string> = {
  Auth: 'Authentication',
  ApplicationUser: 'User Account',
  AuditLogEntry: 'Audit Log',
  SecurityPolicy: 'Security Policy',
  JournalEntry: 'Journal Entry',
  APInvoice: 'AP Invoice',
  ARInvoice: 'AR Invoice',
}

const friendlyArea = (entity: string | null | undefined): string => {
  if (!entity) return ''
  const apiMatch = /^(GET|POST|PUT|PATCH|DELETE)\s+(.+)$/i.exec(entity)
  if (apiMatch) {
    const path = apiMatch[2]
    const hit = AREA_BY_PATH.find((entry) => entry.test.test(path))
    return hit ? hit.label : 'System Activity'
  }
  return FRIENDLY_ENTITY[entity] ?? humanize(entity)
}

const friendlyAction = (action: string | null | undefined): string => {
  if (!action) return ''
  return FRIENDLY_ACTIONS[action] ?? humanize(action)
}

const GUID_PATTERN = /\b[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}\b/i
const HASH64_PATTERN = /\b[0-9a-f]{64}\b/i

const hiddenFieldKeys = new Set(['id', 'recordid', 'path', 'querystring', 'useragent', 'ipaddress', 'checksum', 'hash', 'filepath'])

const asDisplay = (value: unknown): string => {
  if (value === null || value === undefined || value === '') return 'Empty'
  if (typeof value === 'boolean') return value ? 'Yes' : 'No'
  if (typeof value === 'number') return value.toLocaleString()
  if (typeof value === 'string') return value
  try {
    return JSON.stringify(value)
  } catch {
    return 'Unavailable'
  }
}

const isTechnicalValue = (value: string): boolean => GUID_PATTERN.test(value) || HASH64_PATTERN.test(value) || /\/api\//i.test(value)

const pickValue = (source: Record<string, unknown>, keys: string[]): unknown => {
  for (const key of keys) {
    if (Object.hasOwn(source, key)) {
      return source[key]
    }
  }
  return undefined
}

const extractAuditChanges = (detailsJson: string | null | undefined): AuditChange[] => {
  if (!detailsJson) return []

  let parsed: unknown
  try {
    parsed = JSON.parse(detailsJson)
  } catch {
    return []
  }

  const rows: AuditChange[] = []
  const seen = new Set<string>()

  const visit = (node: unknown, depth: number) => {
    if (depth > 6 || node === null || node === undefined) return
    if (Array.isArray(node)) {
      node.forEach((item) => visit(item, depth + 1))
      return
    }
    if (typeof node !== 'object') return

    const obj = node as Record<string, unknown>
    const fieldRaw = pickValue(obj, ['field', 'Field', 'property', 'Property', 'propertyName', 'PropertyName', 'columnName', 'ColumnName', 'name', 'Name'])
    const beforeRaw = pickValue(obj, ['before', 'Before', 'old', 'Old', 'oldValue', 'OldValue', 'originalValue', 'OriginalValue', 'from', 'From'])
    const afterRaw = pickValue(obj, ['after', 'After', 'new', 'New', 'newValue', 'NewValue', 'currentValue', 'CurrentValue', 'to', 'To', 'value', 'Value'])

    if (beforeRaw !== undefined && afterRaw !== undefined) {
      const fieldName = typeof fieldRaw === 'string' ? fieldRaw : 'Value'
      const field = humanize(fieldName)
      const fieldKey = field.toLowerCase().replaceAll(' ', '')
      const before = asDisplay(beforeRaw)
      const after = asDisplay(afterRaw)
      if (before !== after && !hiddenFieldKeys.has(fieldKey) && !(isTechnicalValue(before) && isTechnicalValue(after))) {
        const key = `${field}|${before}|${after}`
        if (!seen.has(key)) {
          seen.add(key)
          rows.push({ field, before, after })
        }
      }
    }

    Object.values(obj).forEach((value) => visit(value, depth + 1))
  }

  visit(parsed, 0)
  return rows.slice(0, 12)
}

export const SystemSettingsModule = () => {
  const location = useLocation()
  const pushToast = useNotificationStore((state) => state.push)
  const user = useAuthStore((state) => state.user)

  const [policies, setPolicies] = useState<SecurityPolicy[]>([])
  const [policyDraft, setPolicyDraft] = useState<Record<string, boolean>>({})
  const [backups, setBackups] = useState<BackupRecord[]>([])
  const [integrations, setIntegrations] = useState<IntegrationSetting[]>([])
  const [auditLogs, setAuditLogs] = useState<AuditLogItem[]>([])
  const [auditTotalCount, setAuditTotalCount] = useState(0)
  const [auditReviewedCount, setAuditReviewedCount] = useState(0)
  const [selectedAuditLog, setSelectedAuditLog] = useState<AuditLogItem | null>(null)
  const [selectedAuditIds, setSelectedAuditIds] = useState<string[]>([])
  const [showAuditSearch, setShowAuditSearch] = useState(false)
  const [auditFilter, setAuditFilter] = useState({ user: '', area: '', action: '' })
  const [busyAction, setBusyAction] = useState<'backup' | 'restore' | 'save-policies' | null>(null)
  const [message, setMessage] = useState('')
  const activeView: SettingsView = viewByHash[location.hash] ?? 'overview'

  const selectedAuditChanges = useMemo(
    () => extractAuditChanges(selectedAuditLog?.details),
    [selectedAuditLog],
  )

  const filteredAuditLogs = useMemo(
    () => auditLogs.filter((item) =>
      (!auditFilter.user || item.user.toLowerCase().includes(auditFilter.user.toLowerCase()))
      && (!auditFilter.area || item.area.toLowerCase().includes(auditFilter.area.toLowerCase()))
      && (!auditFilter.action || item.action.toLowerCase().includes(auditFilter.action.toLowerCase())),
    ),
    [auditFilter.action, auditFilter.area, auditFilter.user, auditLogs],
  )

  const unreviewedFilteredIds = useMemo(
    () => filteredAuditLogs.filter((item) => !item.reviewed).map((item) => item.id),
    [filteredAuditLogs],
  )

  function retainSelectableAuditIds(items: AuditLogItem[]) {
    const allowedIds = new Set(items.filter((item) => !item.reviewed).map((item) => item.id))
    setSelectedAuditIds((current) => current.filter((id) => allowedIds.has(id)))
  }

  const loadSettingsData = async () => {
    try {
      const [policyData, backupData, integrationData, auditRes] = await Promise.all([
        adminService.getSecurityPolicies(),
        adminService.getBackups(),
        adminService.getIntegrations(),
        auditLogsService.getLogs({ page: 1, pageSize: 50 }),
      ])

      const auditItems = ((auditRes.data as {
        items?: Array<{
          id: string
          createdUtc: string
          entity: string
          action: string
          userEmail?: string | null
          performedBy: string
          isReviewed: boolean
          details?: string | null
        }>
      } | undefined)?.items ?? []).map((item) => ({
        id: item.id,
        rawDate: item.createdUtc,
        date: new Date(item.createdUtc).toLocaleString(),
        user: item.userEmail || item.performedBy,
        area: friendlyArea(item.entity),
        action: friendlyAction(item.action),
        reviewed: item.isReviewed,
        details: item.details,
      }))

      setPolicies(policyData)
      setPolicyDraft(Object.fromEntries(policyData.map((policy) => [policy.id, policy.enabled])))
      setBackups(backupData)
      setIntegrations(integrationData)
      const auditMeta = auditRes.data as { totalCount?: number; reviewedCount?: number } | undefined
      setAuditTotalCount(auditMeta?.totalCount ?? auditItems.length)
      setAuditReviewedCount(auditMeta?.reviewedCount ?? auditItems.filter((i) => i.reviewed).length)
      setAuditLogs(auditItems)
      retainSelectableAuditIds(auditItems)
    } catch {
      pushToast('error', 'Unable to load system settings data.')
    }
  }

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    void loadSettingsData()
  }, [])

  const enabledPolicies = useMemo(() => policies.filter((item) => item.enabled).length, [policies])
  const passwordPolicies = useMemo(() => policies.filter((policy) => isPasswordPolicy(policy)), [policies])
  const sessionPolicies = useMemo(() => policies.filter((policy) => isSessionPolicy(policy)), [policies])
  const remainingPolicies = useMemo(
    () => policies.filter((policy) => !isPasswordPolicy(policy) && !isSessionPolicy(policy)),
    [policies],
  )

  const changedPolicyIds = useMemo(
    () =>
      policies
        .filter((policy) => policyDraft[policy.id] !== undefined && policyDraft[policy.id] !== policy.enabled)
        .map((policy) => policy.id),
    [policies, policyDraft],
  )

  const runBackupNow = async () => {
    setBusyAction('backup')

    try {
      await adminService.runBackup()
      await loadSettingsData()
      setBusyAction(null)
      setMessage('Manual backup completed successfully.')
    } catch {
      setBusyAction(null)
      pushToast('error', 'Backup operation failed.')
    }
  }

  const restoreFromLatest = async () => {
    setBusyAction('restore')

    try {
      await adminService.restoreLatestBackup()
      setBusyAction(null)
      setMessage('Restore completed from the latest successful backup.')
    } catch {
      setBusyAction(null)
      pushToast('error', 'Restore operation failed.')
    }
  }

  const savePolicyChanges = async () => {
    if (changedPolicyIds.length === 0) {
      setMessage('No pending changes to save.')
      return
    }

    setBusyAction('save-policies')

    try {
      await Promise.all(changedPolicyIds.map((policyId) => adminService.toggleSecurityPolicy(policyId)))
      await loadSettingsData()
      setBusyAction(null)
      setMessage('Security policies updated successfully.')
    } catch {
      setBusyAction(null)
      pushToast('error', 'Failed to save security policy changes.')
    }
  }

  const handlePolicyToggle = (policyId: string, checked: boolean) => {
    setPolicyDraft((current) => ({
      ...current,
      [policyId]: checked,
    }))
  }

  const toggleAuditSelection = (auditId: string) => {
    setSelectedAuditIds((current) => {
      if (current.includes(auditId)) {
        return current.filter((id) => id !== auditId)
      }

      return [...current, auditId]
    })
  }

  const markAuditLogsReviewed = async () => {
    if (selectedAuditIds.length === 0) {
      pushToast('info', 'Select at least one audit log entry first.')
      return
    }

    try {
      await auditLogsService.markReviewed({
        auditLogIds: selectedAuditIds,
        reviewedBy: user?.fullName || user?.email || 'System Settings',
      })
      pushToast('success', `${selectedAuditIds.length} audit log entries marked reviewed.`)
      setSelectedAuditIds([])
      await loadSettingsData()
    } catch {
      pushToast('error', 'Unable to mark the selected audit logs as reviewed.')
    }
  }

  const renderPolicyCard = (title: string, cardPolicies: SecurityPolicy[]) => (
    <DashboardCard title={title} className="settings-card" key={title}>
      {cardPolicies.length === 0 ? (
        <div className="settings-empty">No policies available.</div>
      ) : (
        <div className="settings-policy-list">
          {cardPolicies.map((policy) => {
            const checked = policyDraft[policy.id] ?? policy.enabled
            return (
              <div className="settings-policy-item" key={policy.id}>
                <div>
                  <div className="settings-policy-title">{policy.name}</div>
                  <p className="settings-policy-description">{policy.description}</p>
                  {renderPolicyValue(policy.value)}
                </div>
                <label className="settings-switch" aria-label={`Toggle ${policy.name}`}>
                  <input
                    type="checkbox"
                    checked={checked}
                    onChange={(event) => handlePolicyToggle(policy.id, event.target.checked)}
                  />
                  <span className="settings-slider" />
                </label>
              </div>
            )
          })}
        </div>
      )}
    </DashboardCard>
  )

  return (
    <section className="settings-scene">
      <div className="settings-header-row">
        <div>
          <h1 className="page-title">{viewTitle[activeView]}</h1>
          <p className="dashboard-hero-subtitle">Configure controls without leaving the main workspace.</p>
        </div>
        {activeView === 'security' && (
          <Button themeColor="primary" onClick={savePolicyChanges} disabled={busyAction === 'save-policies'}>
            {busyAction === 'save-policies' ? 'Saving...' : 'Save Changes'}
          </Button>
        )}
      </div>

      {message && <div className="settings-message">{message}</div>}

      {activeView === 'overview' && (
        <div className="dashboard-grid cols-3">
          <DashboardCard title="Security Policies">
            <div className="kpi-card">
              <div className="kpi-title">Enabled Policies</div>
              <div className="kpi-value">{enabledPolicies}/{policies.length}</div>
              <p className="kpi-subtitle">Policy enforcement status</p>
            </div>
          </DashboardCard>

          <DashboardCard title="Integrations">
            <div className="kpi-card">
              <div className="kpi-title">Connected Services</div>
              <div className="kpi-value">{integrations.length}</div>
              <p className="kpi-subtitle">Active + inactive endpoints</p>
            </div>
          </DashboardCard>

          <DashboardCard title="Audit Logs">
            <div className="kpi-card">
              <div className="kpi-title">Recent Activities</div>
              <div className="kpi-value">{auditLogs.length}</div>
              <p className="kpi-subtitle">Latest events available</p>
            </div>
          </DashboardCard>
        </div>
      )}

      {activeView === 'security' && (
        <div className="dashboard-grid cols-2 settings-security-grid">
          {renderPolicyCard('Password Policy', passwordPolicies)}
          {renderPolicyCard('Session Timeout', sessionPolicies)}
          {renderPolicyCard('Additional Controls', remainingPolicies)}
        </div>
      )}

      {activeView === 'backup' && (
        <div className="settings-page-grid">
          <DashboardCard title="Backup & Restore" className="settings-card">
            <div className="quick-actions" style={{ marginBottom: 0 }}>
              <Button themeColor="primary" disabled={busyAction !== null} onClick={runBackupNow}>
                {busyAction === 'backup' ? 'Running backup...' : 'Run Backup Now'}
              </Button>
              <Button disabled={busyAction !== null} onClick={restoreFromLatest}>
                {busyAction === 'restore' ? 'Restoring...' : 'Restore Latest Backup'}
              </Button>
            </div>
          </DashboardCard>

          <DashboardCard title="Backup History" className="settings-card">
            <div className="settings-stack">
              {backups.length === 0 && (
                <div className="settings-empty">
                  No backups found yet. Run your first backup to establish a restore point.
                </div>
              )}

              {backups.map((backup) => (
                <div key={backup.id} className="settings-record-item">
                  <div className="kpi-with-arrow">
                    <strong>{backup.id}</strong>
                    <Badge
                      themeColor={backup.status === 'success' ? 'success' : 'warning'}
                      data-tooltip={`Backup ${backup.id} completed with status: ${backup.status}. Captured ${backup.timestamp} (${backup.size}, took ${backup.duration}).`}
                    >
                      {backup.status}
                    </Badge>
                  </div>
                  <div className="card-subtitle">{backup.timestamp}</div>
                  <div className="card-subtitle">{backup.size} · {backup.duration}</div>
                </div>
              ))}
            </div>
          </DashboardCard>
        </div>
      )}

      {activeView === 'integrations' && (
        <DashboardCard title="Connected Integrations" className="settings-card">
          <div className="settings-stack">
            {integrations.length === 0 && (
              <div className="settings-empty">
                No integrations configured yet. Once connected, each integration will show endpoint, health status, and last sync time.
              </div>
            )}

            {integrations.map((integration) => (
              <div key={integration.id} className="settings-record-item">
                <div className="kpi-with-arrow">
                  <strong>{integration.name}</strong>
                  <Badge
                    themeColor={getIntegrationThemeColor(integration.status)}
                    data-tooltip={`${integration.name} is currently ${integration.status}. Endpoint: ${integration.endpoint}. Last sync: ${integration.lastSync}.`}
                  >
                    {integration.status}
                  </Badge>
                </div>
                <div className="card-subtitle">{integration.endpoint}</div>
                <div className="card-subtitle">Last sync: {integration.lastSync}</div>
              </div>
            ))}
          </div>
        </DashboardCard>
      )}

      {activeView === 'audit' && (
        <DashboardCard title="Recent Audit Activity" className="settings-card">
          <div style={{ display: 'grid', gap: '1rem' }}>
            <div className="quick-actions" style={{ marginBottom: 0 }}>
              <Button themeColor="primary" onClick={() => setShowAuditSearch(true)}>Search Logs</Button>
              <Button onClick={markAuditLogsReviewed} disabled={selectedAuditIds.length === 0}>Mark Reviewed</Button>
              <Button onClick={() => { setSelectedAuditIds([]); void loadSettingsData() }}>Refresh</Button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '0.75rem' }}>
              <div className="kpi-card">
                <div className="kpi-title">Events</div>
                <div className="kpi-value">{auditTotalCount}</div>
                <p className="kpi-subtitle">Latest tracked admin and system actions</p>
              </div>
              <div className="kpi-card">
                <div className="kpi-title">Reviewed</div>
                <div className="kpi-value">{auditReviewedCount}</div>
                <p className="kpi-subtitle">Entries already acknowledged</p>
              </div>
              <div className="kpi-card">
                <div className="kpi-title">Selected</div>
                <div className="kpi-value">{selectedAuditIds.length}</div>
                <p className="kpi-subtitle">Ready to mark as reviewed</p>
              </div>
            </div>

            {filteredAuditLogs.length === 0 ? (
              <div className="settings-empty">
                No audit log entries match the current filters.
              </div>
            ) : (
              <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                  <thead>
                    <tr style={{ background: '#f8fafc' }}>
                      <th style={{ textAlign: 'left', padding: '0.75rem', borderBottom: '1px solid #e5e7eb', width: 44 }}>
                        <input
                          type="checkbox"
                          checked={unreviewedFilteredIds.length > 0 && unreviewedFilteredIds.every((id) => selectedAuditIds.includes(id))}
                          onChange={(event) => setSelectedAuditIds(event.target.checked ? unreviewedFilteredIds : [])}
                          title="Select all unreviewed"
                        />
                      </th>
                      <th style={{ textAlign: 'left', padding: '0.75rem', borderBottom: '1px solid #e5e7eb' }}>Date & Time</th>
                      <th style={{ textAlign: 'left', padding: '0.75rem', borderBottom: '1px solid #e5e7eb' }}>Action</th>
                      <th style={{ textAlign: 'left', padding: '0.75rem', borderBottom: '1px solid #e5e7eb' }}>User</th>
                      <th style={{ textAlign: 'left', padding: '0.75rem', borderBottom: '1px solid #e5e7eb' }}>Status</th>
                      <th style={{ textAlign: 'right', padding: '0.75rem', borderBottom: '1px solid #e5e7eb' }}></th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredAuditLogs.map((item) => (
                      <tr key={item.id}>
                        <td style={{ padding: '0.75rem', borderBottom: '1px solid #f1f5f9' }}>
                          {!item.reviewed && (
                            <input
                              type="checkbox"
                              checked={selectedAuditIds.includes(item.id)}
                              onChange={() => toggleAuditSelection(item.id)}
                            />
                          )}
                        </td>
                        <td style={{ padding: '0.75rem', borderBottom: '1px solid #f1f5f9' }}>{item.date}</td>
                        <td style={{ padding: '0.75rem', borderBottom: '1px solid #f1f5f9' }}>{item.action} {item.area}</td>
                        <td style={{ padding: '0.75rem', borderBottom: '1px solid #f1f5f9' }}>{item.user}</td>
                        <td style={{ padding: '0.75rem', borderBottom: '1px solid #f1f5f9' }}>
                          <span style={{ color: item.reviewed ? '#15803d' : '#64748b', fontSize: '0.82rem', fontWeight: 600 }}>
                            {item.reviewed ? 'Reviewed' : 'Pending review'}
                          </span>
                        </td>
                        <td style={{ padding: '0.75rem', borderBottom: '1px solid #f1f5f9', textAlign: 'right' }}>
                          <Button size="small" onClick={() => setSelectedAuditLog(item)}>View Details</Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </DashboardCard>
      )}

      {selectedAuditLog && (
        <Dialog title="Activity Details" onClose={() => setSelectedAuditLog(null)} width={820}>
          <div style={{ display: 'grid', gap: '1rem' }}>
            <section>
              <h3 style={{ margin: '0 0 0.4rem', color: '#1f4f8a' }}>Overview</h3>
              <div style={{ display: 'grid', gap: '0.2rem' }}>
                <div style={{ fontSize: '1.05rem', fontWeight: 600 }}>{selectedAuditLog.user}</div>
                <div style={{ fontSize: '1.4rem', fontWeight: 700 }}>{selectedAuditLog.action} {selectedAuditLog.area}</div>
                <div style={{ color: '#64748b' }}>{selectedAuditLog.date}</div>
              </div>
            </section>

            <section style={{ borderTop: '1px solid #e5e7eb', paddingTop: '1rem' }}>
              <h3 style={{ margin: '0 0 0.6rem' }}>Changes Made</h3>
              {selectedAuditChanges.length === 0 ? (
                <p style={{ margin: 0, color: '#64748b' }}>
                  No field-level before and after values were captured for this activity.
                </p>
              ) : (
                <div style={{ overflowX: 'auto' }}>
                  <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead>
                      <tr style={{ background: '#f8fafc' }}>
                        <th style={{ textAlign: 'left', padding: '0.65rem', borderBottom: '1px solid #e5e7eb' }}>Field</th>
                        <th style={{ textAlign: 'left', padding: '0.65rem', borderBottom: '1px solid #e5e7eb' }}>Before</th>
                        <th style={{ textAlign: 'left', padding: '0.65rem', borderBottom: '1px solid #e5e7eb' }}>After</th>
                      </tr>
                    </thead>
                    <tbody>
                      {selectedAuditChanges.map((change) => (
                        <tr key={`${change.field}-${change.before}-${change.after}`}>
                          <td style={{ padding: '0.65rem', borderBottom: '1px solid #f1f5f9', fontWeight: 600 }}>{change.field}</td>
                          <td style={{ padding: '0.65rem', borderBottom: '1px solid #f1f5f9' }}>{change.before}</td>
                          <td style={{ padding: '0.65rem', borderBottom: '1px solid #f1f5f9', background: 'rgba(37, 99, 235, 0.08)' }}>{change.after}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </section>

            <section style={{ borderTop: '1px solid #e5e7eb', paddingTop: '1rem' }}>
              <h3 style={{ margin: '0 0 0.5rem' }}>Context</h3>
              <p style={{ margin: 0 }}><strong>Related Module:</strong> {selectedAuditLog.area}</p>
            </section>
          </div>
          <DialogActionsBar>
            <Button onClick={() => setSelectedAuditLog(null)}>Close</Button>
          </DialogActionsBar>
        </Dialog>
      )}

      {showAuditSearch && (
        <Dialog title="Search Audit Logs" onClose={() => setShowAuditSearch(false)}>
          <div style={{ minWidth: '520px', display: 'grid', gap: '0.75rem' }}>
            <div>
              <label htmlFor="settings-audit-user-filter">User</label>
              <Input
                id="settings-audit-user-filter"
                value={auditFilter.user}
                onChange={(event: InputChangeEvent) => setAuditFilter((current) => ({ ...current, user: String(event.target.value) }))}
              />
            </div>
            <div>
              <label htmlFor="settings-audit-area-filter">Module</label>
              <Input
                id="settings-audit-area-filter"
                value={auditFilter.area}
                onChange={(event: InputChangeEvent) => setAuditFilter((current) => ({ ...current, area: String(event.target.value) }))}
              />
            </div>
            <div>
              <label htmlFor="settings-audit-action-filter">Action</label>
              <Input
                id="settings-audit-action-filter"
                value={auditFilter.action}
                onChange={(event: InputChangeEvent) => setAuditFilter((current) => ({ ...current, action: String(event.target.value) }))}
              />
            </div>
          </div>
          <DialogActionsBar>
            <Button themeColor="primary" onClick={() => setShowAuditSearch(false)}>Apply Filter</Button>
            <Button onClick={() => { setAuditFilter({ user: '', area: '', action: '' }); setShowAuditSearch(false) }}>Clear Filter</Button>
          </DialogActionsBar>
        </Dialog>
      )}
    </section>
  )
}

