const getInitials = (name: string) => {
  const parts = name.trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) {
    return 'NA'
  }

  if (parts.length === 1) {
    return parts[0].slice(0, 2).toUpperCase()
  }

  return `${parts[0][0] ?? ''}${parts.at(-1)?.[0] ?? ''}`.toUpperCase()
}

const getErrorMessage = (error: unknown, fallback: string) => {
  const responseMessage = (error as AxiosError<{ message?: string }>)?.response?.data?.message
  return typeof responseMessage === 'string' && responseMessage.trim().length > 0
    ? responseMessage
    : fallback
}

const splitPasswordTerms = (value?: string) => (value ?? DEFAULT_PASSWORD_POLICY.blockedTerms)
  .split(/[\r\n,;]+/)
  .map((term) => term.trim().toLowerCase())
  .filter((term) => term.length >= 3)

const getPasswordPolicyIssues = (
  password: string,
  employee: Employee | null,
  policy: SecurityPolicySettings['password'],
) => {
  const issues: string[] = []
  const normalized = password.toLowerCase()

  if (password.length < policy.minLength) {
    issues.push(`Use at least ${policy.minLength} characters.`)
  }

  if (password.length > policy.maxLength) {
    issues.push(`Use no more than ${policy.maxLength} characters.`)
  }

  if (splitPasswordTerms(policy.blockedTerms).some((term) => normalized.includes(term))) {
    issues.push('Avoid common, compromised, or dictionary-style words.')
  }

  if (policy.forbidCompanyName && normalized.includes('cmnetwork')) {
    issues.push('Do not include the company name.')
  }

  if (policy.forbidUserContext && employee) {
    const contextualTerms = [
      employee.email,
      employee.email.split('@')[0],
      ...employee.fullName.split(/\s+/),
    ]
      .flatMap((term) => term.split(/[@._\-\s]+/))
      .map((term) => term.trim().toLowerCase())
      .filter((term) => term.length >= 3)

    if (contextualTerms.some((term) => normalized.includes(term))) {
      issues.push('Do not include the user name, username, or email terms.')
    }
  }

  return issues
}

const getCreateFormValidationError = (formData: EmployeeFormData) => {
  const missingFields: string[] = []

  if (!formData.firstName.trim()) {
    missingFields.push('First Name')
  }

  if (!formData.lastName.trim()) {
    missingFields.push('Last Name')
  }

  if (!formData.birthdate.trim()) {
    missingFields.push('Birthdate')
  }

  if (!formData.address.trim()) {
    missingFields.push('Address')
  }

  if (missingFields.length > 0) {
    return `Please complete required field(s): ${missingFields.join(', ')}.`
  }

  if (!isValidBirthdate(formData.birthdate)) {
    return 'Please enter a valid birthdate.'
  }

  const computedAge = formData.age === '' ? calculateAge(formData.birthdate) : Number(formData.age)
  if (computedAge < 18) {
    return 'Employee must be at least 18 years old.'
  }

  return null
}

const getUserSummary = (users: Employee[]): UserSummary => ({
  active: users.filter((employee) => employee.status === 'active').length,
  pending: users.filter((employee) => employee.status === 'pending').length,
  total: users.length,
})

export const UserManagementModule = () => {
  const user = useAuthStore((state) => state.user)
  const selectedRole = useAuthStore((state) => state.selectedRole)
  const pushToast = useNotificationStore((state) => state.push)
  const currentRole = selectedRole || user?.role || 'super-admin'

  const [employees, setEmployees] = useState<Employee[]>([])
  const [showCreateDialog, setShowCreateDialog] = useState(false)
  const [showEditDialog, setShowEditDialog] = useState(false)
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
  const [showPasswordDialog, setShowPasswordDialog] = useState(false)
  const [selectedEmployee, setSelectedEmployee] = useState<Employee | null>(null)
  const [formData, setFormData] = useState<EmployeeFormData>(emptyFormData)
  const [savingUser, setSavingUser] = useState(false)
  const [passwordForm, setPasswordForm] = useState({ newPassword: '', confirmPassword: '' })
  const [passwordPolicy, setPasswordPolicy] = useState<SecurityPolicySettings['password']>(DEFAULT_PASSWORD_POLICY)
  const [showNewPassword, setShowNewPassword] = useState(false)
  const [showConfirmPassword, setShowConfirmPassword] = useState(false)
  const [savingPassword, setSavingPassword] = useState(false)
  const [searchTerm, setSearchTerm] = useState('')
  const [roleFilter, setRoleFilter] = useState<'all' | Role>('all')
  const [departmentFilter, setDepartmentFilter] = useState('all')
  const [page, setPage] = useState(1)
  const [totalCount, setTotalCount] = useState(0)
  const [loadingUsers, setLoadingUsers] = useState(false)
  const [directoryDepartments, setDirectoryDepartments] = useState<string[]>([])
  const [departmentOptions, setDepartmentOptions] = useState<DepartmentOption[]>([])
  const [userSummary, setUserSummary] = useState<UserSummary>({ active: 0, pending: 0, total: 0 })
  const currentPasswordIssues = getPasswordPolicyIssues(passwordForm.newPassword, selectedEmployee, passwordPolicy)

  const loadUserSummary = async () => {
    try {
      const users = await adminService.getUsers()
      setUserSummary(getUserSummary(users))
      setDirectoryDepartments(
        [...new Set(users.map((item) => item.department))]
          .filter((value) => value && value.trim().length > 0)
          .sort((a, b) => a.localeCompare(b)),
      )
    } catch {
      pushToast('error', 'Failed to load user totals.')
    }
  }

  const loadPasswordPolicy = async () => {
    try {
      const settings = await adminService.getSecurityPolicySettings()
      setPasswordPolicy(settings.password)
    } catch {
      setPasswordPolicy(DEFAULT_PASSWORD_POLICY)
    }
  }

  const loadDepartmentOptions = async () => {
    try {
      const items = await adminService.getDepartments()
      setDepartmentOptions(items)
    } catch {
      setDepartmentOptions([])
      pushToast('warning', 'Unable to load departments for the employee form.')
    }
  }

  const loadUsers = async (query?: Partial<DirectoryQuery>) => {
    const nextSearch = query?.search ?? searchTerm
    const nextRole = query?.role ?? roleFilter
    const nextDepartment = query?.department ?? departmentFilter
    const nextPage = query?.page ?? page

    try {
      setLoadingUsers(true)
      const response = await adminService.getUsersPaged({
        search: nextSearch.trim().length > 0 ? nextSearch.trim() : undefined,
        role: nextRole === 'all' ? undefined : nextRole,
        department: nextDepartment === 'all' ? undefined : nextDepartment,
        page: nextPage,
        pageSize: PAGE_SIZE,
      })

      setEmployees(response.items)
      setTotalCount(response.totalCount)
      setDirectoryDepartments((current) => {
        const merged = [...new Set([...current, ...response.items.map((item) => item.department)])]
        return merged.filter((value) => value && value.trim().length > 0).sort((a, b) => a.localeCompare(b))
      })
    } catch {
      pushToast('error', 'Failed to load users.')
    } finally {
      setLoadingUsers(false)
    }
  }

  const resetDirectoryFilters = () => {
    setSearchTerm('')
    setRoleFilter('all')
    setDepartmentFilter('all')
    setPage(1)
  }

  useEffect(() => {
    void loadUsers()
  }, [departmentFilter, page, roleFilter, searchTerm])

  useEffect(() => {
    void loadUserSummary()
    void loadPasswordPolicy()
    void loadDepartmentOptions()
  }, [])

  const handleCreateClick = () => {
    setFormData(emptyFormData)
    setShowCreateDialog(true)
  }

  const handleEditClick = (emp: Employee) => {
    const splitName = emp.fullName.split(' ')
    setSelectedEmployee(emp)
    setFormData({
      ...emptyFormData,
      firstName: splitName[0] || '',
      middleName: splitName.length > 2 ? splitName.slice(1, -1).join(' ') : '',
      lastName: splitName.length > 1 ? (splitName.at(-1) ?? '') : '',
      department: emp.department,
      role: emp.role,
      status: emp.status,
    })
    setShowEditDialog(true)
  }

  const handleDeleteClick = (emp: Employee) => {
    setSelectedEmployee(emp)
    setShowDeleteConfirm(true)
  }

  const handlePasswordClick = (emp: Employee) => {
    if (isSuperAdminRole(emp.role)) {
      pushToast('warning', 'Superadmin passwords cannot be changed here.')
      return
    }

    setSelectedEmployee(emp)
    setPasswordForm({ newPassword: '', confirmPassword: '' })
    setShowNewPassword(false)
    setShowConfirmPassword(false)
    setShowPasswordDialog(true)
  }

  const handleUnlockClick = async (emp: Employee) => {
    try {
      await adminService.unlockUser(emp.id)
      pushToast('success', `Account unlocked for ${emp.fullName}.`)
    } catch {
      pushToast('error', `Failed to unlock account for ${emp.fullName}.`)
    }
  }

  const validateCreateForm = (): boolean => {
    const validationError = getCreateFormValidationError(formData)
    if (validationError) {
      pushToast('error', validationError)
      return false
    }

    return true
  }

  const handleBirthdateChange = (value: string) => {
    const computedAge = calculateAge(value)
    setFormData((current) => ({
      ...current,
      birthdate: value,
      age: computedAge || '',
    }))
  }

  const handleSaveCreate = async () => {
    if (!validateCreateForm()) {
      return
    }

    setSavingUser(true)

    try {
      const computedAge = formData.age === '' ? calculateAge(formData.birthdate) : Number(formData.age)

      const generatedEmail = `${formData.firstName}.${formData.lastName}`
        .toLowerCase()
        .replaceAll(' ', '.')
        .concat('@cmnetwork.com')

      const generatedPassword = generateCreatePassword()

      const payload = {
        firstName: formData.firstName,
        lastName: formData.lastName,
        middleName: formData.middleName,
        birthdate: formData.birthdate,
        gender: formData.gender,
        age: computedAge,
        address: formData.address,
        tinNumber: formData.tinNumber,
        sssNumber: formData.sssNumber,
        role: formData.role,
        department: formData.department || null,
        generatedEmail,
        generatedPassword,
      }

      await adminService.createUser(payload)
      await Promise.all([loadUsers(), loadUserSummary()])
      setShowCreateDialog(false)
      pushToast('success', `Employee account created successfully. Login email: ${generatedEmail}`)
    } catch (error) {
      pushToast('error', getErrorMessage(error, 'Unable to create employee account.'))
    } finally {
      setSavingUser(false)
    }
  }

  const handleSaveEdit = async () => {
    if (!selectedEmployee) return

    try {
      await adminService.updateUser(selectedEmployee.id, {
        firstName: formData.firstName,
        middleName: formData.middleName,
        lastName: formData.lastName,
        department: formData.department || null,
        role: formData.role,
        status: formData.status,
      })

      await Promise.all([loadUsers(), loadUserSummary()])
      setShowEditDialog(false)
      setSelectedEmployee(null)
      pushToast('success', 'Employee updated successfully.')
    } catch (error) {
      pushToast('error', getErrorMessage(error, 'Unable to update employee account.'))
    }
  }

  const handleSavePassword = async () => {
    if (!selectedEmployee) return

    if (currentPasswordIssues.length > 0) {
      pushToast('error', currentPasswordIssues.join(' '))
      return
    }

    if (passwordForm.newPassword !== passwordForm.confirmPassword) {
      pushToast('error', 'Passwords do not match.')
      return
    }

    setSavingPassword(true)

    try {
      await adminService.resetUserPassword(selectedEmployee.id, { newPassword: passwordForm.newPassword })
      resetDirectoryFilters()
      await Promise.all([
        loadUsers({ search: '', role: 'all', department: 'all', page: 1 }),
        loadUserSummary(),
      ])
      setShowPasswordDialog(false)
      setSelectedEmployee(null)
      setPasswordForm({ newPassword: '', confirmPassword: '' })
      setShowNewPassword(false)
      setShowConfirmPassword(false)
      pushToast('success', `Password updated for ${selectedEmployee.fullName}.`)
    } catch (error) {
      pushToast('error', getErrorMessage(error, 'Unable to update user password.'))
    } finally {
      setSavingPassword(false)
    }
  }

  const handleClosePasswordDialog = () => {
    setShowPasswordDialog(false)
    setShowNewPassword(false)
    setShowConfirmPassword(false)
    setPasswordForm({ newPassword: '', confirmPassword: '' })
  }

  const handleConfirmDelete = async () => {
    if (!selectedEmployee) return

    try {
      await adminService.deleteUser(selectedEmployee.id)
      await Promise.all([loadUsers(), loadUserSummary()])
      setShowDeleteConfirm(false)
      setSelectedEmployee(null)
      pushToast('warning', 'Employee account deleted.')
    } catch {
      pushToast('error', 'Unable to delete employee account.')
    }
  }

  const totalPages = Math.max(1, Math.ceil(totalCount / PAGE_SIZE))
  const safePage = Math.min(page, totalPages)
  const startRow = totalCount === 0 ? 0 : (safePage - 1) * PAGE_SIZE + 1
  const endRow = Math.min(safePage * PAGE_SIZE, totalCount)
  const hasDirectoryFilters = searchTerm.trim().length > 0 || roleFilter !== 'all' || departmentFilter !== 'all'
  const filteredResultLabel = totalCount === 1 ? ' filtered result' : ' filtered results'
  const paginationFilterLabel = hasDirectoryFilters ? filteredResultLabel : ''
  const emptyUsersMessage = loadingUsers ? 'Loading users...' : 'No users match your search and filters.'

  useEffect(() => {
    setPage(1)
  }, [departmentFilter, roleFilter, searchTerm])

  return (
    <section style={{ padding: '0' }}>
      <div style={{ marginBottom: '24px' }}>
        <h1 className="page-title">
          Welcome, {user?.fullName} - {roleLabels[currentRole]} Dashboard
        </h1>
      </div>

      <div className="dashboard-grid cols-3" style={{ marginBottom: '24px' }}>
        <DashboardCard title="Active Users">
          <div className="kpi-card">
            <div className="kpi-title">Total Active</div>
            <div className="kpi-value">{userSummary.active}</div>
            <p className="kpi-subtitle">Employees with access</p>
          </div>
        </DashboardCard>

        <DashboardCard title="Pending Invitations">
          <div className="kpi-card">
            <div className="kpi-title">Awaiting Activation</div>
            <div className="kpi-value">{userSummary.pending}</div>
            <p className="kpi-subtitle">New hires and transfers</p>
          </div>
        </DashboardCard>

        <DashboardCard title="Total Users">
          <div className="kpi-card">
            <div className="kpi-title">Overall Count</div>
            <div className="kpi-value">{userSummary.total}</div>
            <p className="kpi-subtitle">Active + Pending + Inactive</p>
          </div>
        </DashboardCard>
      </div>

      <div style={{ marginBottom: '16px' }}>
        <Button themeColor="primary" className="um-create-btn" onClick={handleCreateClick}>
          Create Employee Account
        </Button>
      </div>

      <DashboardCard title="Employee Directory">
        <div className="um-toolbar">
          <Input
            value={searchTerm}
            onChange={(event: InputChangeEvent) => setSearchTerm(String(event.value ?? ''))}
            placeholder="Search by name or email"
            className="um-search"
          />
          <select
            value={departmentFilter}
            onChange={(event) => setDepartmentFilter(event.target.value)}
            className="role-select um-filter"
          >
            <option value="all">Filter by Department</option>
            {directoryDepartments.map((department) => (
              <option key={department} value={department}>{department}</option>
            ))}
          </select>
          <select
            value={roleFilter}
            onChange={(event) => setRoleFilter(event.target.value as 'all' | Role)}
            className="role-select um-filter"
          >
            <option value="all">Filter by Role</option>
            {ROLES.map((role) => (
              <option key={role} value={role}>{roleLabels[role]}</option>
            ))}
          </select>
        </div>

        {hasDirectoryFilters && (
          <div className="um-filter-status">
            <span>{totalCount} matching {totalCount === 1 ? 'user' : 'users'} from {userSummary.total} total users</span>
            <Button size="small" fillMode="flat" onClick={resetDirectoryFilters}>Clear filters</Button>
          </div>
        )}

        <div style={{ overflowX: 'auto' }}>
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Department</th>
                <th>Role</th>
                <th>Status</th>
                <th>Join Date</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {employees.map((emp) => (
                <UserDirectoryRow
                  key={emp.id}
                  employee={emp}
                  onEdit={handleEditClick}
                  onPassword={handlePasswordClick}
                  onUnlock={handleUnlockClick}
                  onDelete={handleDeleteClick}
                />
              ))}
              {employees.length === 0 && (
                <tr>
                  <td colSpan={7} className="um-empty-state">
                    {emptyUsersMessage}
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="um-pagination">
          <span>
            Showing {startRow}-{endRow} of {totalCount}{paginationFilterLabel}
          </span>
          <div className="um-pagination-actions">
            <Button size="small" fillMode="outline" disabled={safePage <= 1} onClick={() => setPage((current) => Math.max(1, current - 1))}>
              Previous
            </Button>
            <span className="um-page-label">Page {safePage} of {totalPages}</span>
            <Button size="small" fillMode="outline" disabled={safePage >= totalPages} onClick={() => setPage((current) => Math.min(totalPages, current + 1))}>
              Next
            </Button>
          </div>
        </div>
      </DashboardCard>

      {showCreateDialog && (
        <Dialog title="Create Employee Account" onClose={() => setShowCreateDialog(false)}>
          <div
            style={{
              padding: '16px',
              width: 'min(620px, 92vw)',
              maxHeight: 'calc(100vh - 220px)',
              overflowY: 'auto',
              overflowX: 'hidden',
            }}
          >
            <div style={{ display: 'grid', gap: '16px', paddingRight: '4px' }}>
              <div>
                <label htmlFor="create-first-name">First Name</label>
                <Input id="create-first-name" value={formData.firstName} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, firstName: String(e.value ?? '') }))} />
              </div>

              <div>
                <label htmlFor="create-middle-name">Middle Name</label>
                <Input id="create-middle-name" value={formData.middleName} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, middleName: String(e.value ?? '') }))} />
              </div>

              <div>
                <label htmlFor="create-last-name">Last Name</label>
                <Input id="create-last-name" value={formData.lastName} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, lastName: String(e.value ?? '') }))} />
              </div>

              <div>
                <label htmlFor="create-birthdate">Birthdate</label>
                <input
                  id="create-birthdate"
                  type="date"
                  value={formData.birthdate}
                  onChange={(event) => handleBirthdateChange(event.target.value)}
                  className="role-select"
                  style={{ width: '100%' }}
                />
              </div>

              <div>
                <label htmlFor="create-gender">Gender</label>
                <select
                  id="create-gender"
                  value={formData.gender}
                  onChange={(event) => setFormData((current) => ({ ...current, gender: event.target.value as EmployeeFormData['gender'] }))}
                  className="role-select"
                  style={{ width: '100%' }}
                >
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
                </select>
              </div>

              <div>
                <label htmlFor="create-age">Age (must be 18+)</label>
                <Input
                  id="create-age"
                  type="number"
                  value={String(formData.age)}
                  onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, age: Number(e.value) || '' }))}
                />
              </div>

              <div>
                <label htmlFor="create-address">Address</label>
                <TextArea
                  id="create-address"
                  value={formData.address}
                  onChange={(e: TextAreaChangeEvent) => setFormData((current) => ({ ...current, address: String(e.value ?? '') }))}
                  rows={3}
                />
              </div>

              <div>
                <label htmlFor="create-tin">TIN Number</label>
                <MaskedTextBox
                  id="create-tin"
                  mask="000-000-000-000"
                  value={formData.tinNumber}
                  onChange={(event) => setFormData((current) => ({ ...current, tinNumber: String(event.value ?? '') }))}
                />
              </div>

              <div>
                <label htmlFor="create-sss">SSS Number</label>
                <MaskedTextBox
                  id="create-sss"
                  mask="00-0000000-0"
                  value={formData.sssNumber}
                  onChange={(event) => setFormData((current) => ({ ...current, sssNumber: String(event.value ?? '') }))}
                />
              </div>

              <div>
                <label htmlFor="create-role">Role Assignment</label>
                <select
                  id="create-role"
                  value={formData.role}
                  onChange={(event) => setFormData((current) => ({ ...current, role: event.target.value as Role }))}
                  className="role-select"
                  style={{ width: '100%' }}
                >
                  {ROLES.map((role) => (
                    <option key={role} value={role}>{roleLabels[role]}</option>
                  ))}
                </select>
              </div>

              <div>
                <label htmlFor="create-department">Department (optional for non-faculty)</label>
                <select
                  id="create-department"
                  value={formData.department}
                  onChange={(event) => setFormData((current) => ({ ...current, department: event.target.value }))}
                  className="role-select"
                  style={{ width: '100%' }}
                >
                  <option value="">Unassigned</option>
                  {departmentOptions.map((department) => (
                    <option key={department.id} value={department.name}>
                      {department.code} - {department.name}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>
          <DialogActionsBar>
            <Button themeColor="primary" onClick={handleSaveCreate} disabled={savingUser}>
              {savingUser ? 'Saving...' : 'Save Employee'}
            </Button>
            <Button onClick={() => setShowCreateDialog(false)}>Cancel</Button>
          </DialogActionsBar>
        </Dialog>
      )}

      {showEditDialog && selectedEmployee && (
        <Dialog title={`Edit User - ${selectedEmployee.fullName}`} onClose={() => setShowEditDialog(false)}>
          <div style={{ padding: '16px', minWidth: '480px', display: 'grid', gap: '16px' }}>
            <div>
              <label htmlFor="edit-first-name">First Name</label>
              <Input id="edit-first-name" value={formData.firstName} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, firstName: String(e.value ?? '') }))} />
            </div>
            <div>
              <label htmlFor="edit-middle-name">Middle Name</label>
              <Input id="edit-middle-name" value={formData.middleName} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, middleName: String(e.value ?? '') }))} />
            </div>
            <div>
              <label htmlFor="edit-last-name">Last Name</label>
              <Input id="edit-last-name" value={formData.lastName} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, lastName: String(e.value ?? '') }))} />
            </div>
            <div>
              <label htmlFor="edit-department">Department</label>
              <Input id="edit-department" value={formData.department} onChange={(e: InputChangeEvent) => setFormData((current) => ({ ...current, department: String(e.value ?? '') }))} />
            </div>
            <div>
              <label htmlFor="edit-status">Status</label>
              <select
                id="edit-status"
                value={formData.status}
                onChange={(event) => setFormData((current) => ({ ...current, status: event.target.value as EmployeeFormData['status'] }))}
                className="role-select"
                style={{ width: '100%' }}
              >
                <option value="active">Active</option>
                <option value="pending">Pending</option>
                <option value="inactive">Inactive</option>
              </select>
            </div>
          </div>
          <DialogActionsBar>
            <Button themeColor="primary" onClick={handleSaveEdit}>Save Changes</Button>
            <Button onClick={() => setShowEditDialog(false)}>Cancel</Button>
          </DialogActionsBar>
        </Dialog>
      )}

      {showDeleteConfirm && selectedEmployee && (
        <Dialog title="Confirm Delete" onClose={() => setShowDeleteConfirm(false)}>
          <div style={{ padding: '16px' }}>
            <p>Are you sure you want to delete <strong>{selectedEmployee.fullName}</strong>?</p>
          </div>
          <DialogActionsBar>
            <Button themeColor="error" onClick={handleConfirmDelete}>Delete User</Button>
            <Button onClick={() => setShowDeleteConfirm(false)}>Cancel</Button>
          </DialogActionsBar>
        </Dialog>
      )}

      <PasswordResetDialog
        employee={selectedEmployee}
        isOpen={showPasswordDialog}
        passwordForm={passwordForm}
        passwordPolicy={passwordPolicy}
        passwordIssues={currentPasswordIssues}
        showNewPassword={showNewPassword}
        showConfirmPassword={showConfirmPassword}
        savingPassword={savingPassword}
        onNewPasswordChange={(value) => setPasswordForm((current) => ({ ...current, newPassword: value }))}
        onConfirmPasswordChange={(value) => setPasswordForm((current) => ({ ...current, confirmPassword: value }))}
        onToggleNewPassword={() => setShowNewPassword((current) => !current)}
        onToggleConfirmPassword={() => setShowConfirmPassword((current) => !current)}
        onSave={handleSavePassword}
        onClose={handleClosePasswordDialog}
      />
    </section>
  )
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import { Button } from '@progress/kendo-react-buttons'
import { Dialog, DialogActionsBar } from '@progress/kendo-react-dialogs'
import { Input, type InputChangeEvent } from '@progress/kendo-react-inputs'
import type { ColumnDef } from '@tanstack/react-table'
import { DashboardCard } from '../../components/DashboardCard'
import { DataTable } from '../../components/ui/data-table'
import { vendorService, type Vendor } from '../../services/vendorCustomerService'
import { useAuthStore } from '../../store/authStore'
import { useNotificationStore } from '../../store/notificationStore'
import {
  createVendorSchema,
  updateVendorSchema,
  type CreateVendorInput,
  type UpdateVendorInput,
} from '../../schemas/vendorCustomerSchemas'

interface VendorFormData {
  vendorCode: string
  name: string
  contactPerson: string
  email: string
  phoneNumber: string
  address: string
  city: string
  state: string
  postalCode: string
  country: string
  taxId: string
  creditLimit: string
  paymentTerms: string
  isActive: boolean
}

const defaultFormData: VendorFormData = {
  vendorCode: '',
  name: '',
  contactPerson: '',
  email: '',
  phoneNumber: '',
  address: '',
  city: '',
  state: '',
  postalCode: '',
  country: '',
  taxId: '',
  creditLimit: '',
  paymentTerms: '',
  isActive: true,
}

const formatCurrency = (value: number) =>
  new Intl.NumberFormat('en-PH', {
    style: 'currency',
    currency: 'PHP',
  }).format(value)

export function VendorsModule() {
  const { user } = useAuthStore()
  const push = useNotificationStore((state) => state.push)

  const [vendors, setVendors] = useState<Vendor[]>([])
  const [loading, setLoading] = useState(false)
  const [showDialog, setShowDialog] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [formData, setFormData] = useState<VendorFormData>(defaultFormData)
  const [formErrors, setFormErrors] = useState<Record<string, string>>({})
  const [searchText, setSearchText] = useState('')

  const loadVendors = useCallback(async () => {
    try {
      setLoading(true)
      const response = await vendorService.getVendors()
      setVendors(response.data)
    } catch {
      push('error', 'Failed to load vendors')
    } finally {
      setLoading(false)
    }
  }, [push])

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    loadVendors()
  }, [loadVendors])

  const filteredVendors = searchText
    ? vendors.filter(
        (v) =>
          v.vendorCode.toLowerCase().includes(searchText.toLowerCase()) ||
          v.name.toLowerCase().includes(searchText.toLowerCase()),
      )
    : vendors

  const vendorColumns = useMemo<ColumnDef<Vendor>[]>(
    () => [
      { accessorKey: 'vendorCode', header: 'Code' },
      { accessorKey: 'name', header: 'Vendor Name' },
      { accessorKey: 'contactPerson', header: 'Contact' },
      { accessorKey: 'city', header: 'City' },
      { accessorKey: 'country', header: 'Country' },
      {
        id: 'creditLimit',
        header: 'Credit Limit',
        cell: ({ row }) => formatCurrency(row.original.creditLimit),
      },
      {
        id: 'isActive',
        header: 'Active',
        cell: ({ row }) => (row.original.isActive ? 'Yes' : 'No'),
      },
      {
        id: 'actions',
        header: 'Actions',
        cell: ({ row }) => (
          <div className="flex gap-2">
            <Button
              icon="edit"
              onClick={() => handleEditClick(row.original)}
              style={{ marginRight: '8px' }}
            />
            <Button icon="delete" onClick={() => handleDeleteClick(row.original)} />
          </div>
        ),
      },
    ],
    [],
  )

  const handleAddClick = () => {
    setEditingId(null)
    setFormData(defaultFormData)
    setFormErrors({})
    setShowDialog(true)
  }

  const handleEditClick = (vendor: Vendor) => {
    setEditingId(vendor.id)
    setFormData({
      vendorCode: vendor.vendorCode,
      name: vendor.name,
      contactPerson: vendor.contactPerson || '',
      email: vendor.email || '',
      phoneNumber: vendor.phoneNumber || '',
      address: vendor.address || '',
      city: vendor.city || '',
      state: vendor.state || '',
      postalCode: vendor.postalCode || '',
      country: vendor.country || '',
      taxId: vendor.taxId || '',
      creditLimit: vendor.creditLimit.toString(),
      paymentTerms: vendor.paymentTerms || '',
      isActive: vendor.isActive,
    })
    setFormErrors({})
    setShowDialog(true)
  }

  const handleDeleteClick = async (vendor: Vendor) => {
    if (confirm(`Delete vendor "${vendor.name}"?`)) {
      try {
        await vendorService.deleteVendor(vendor.id)
        push('success', 'Vendor deleted successfully')
        await loadVendors()
      } catch {
        push('error', 'Failed to delete vendor')
      }
    }
  }

  const handleFormChange = (e: InputChangeEvent | React.ChangeEvent<HTMLInputElement>) => {
    const target = e.target as HTMLInputElement
    const { name, value, type, checked } = target
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }))
    // Clear error for this field
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const newErrors = { ...prev }
        delete newErrors[name]
        return newErrors
      })
    }
  }

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {}
    const submitData = {
      vendorCode: formData.vendorCode,
      name: formData.name,
      contactPerson: formData.contactPerson ? formData.contactPerson : undefined,
      email: formData.email ? formData.email : undefined,
      phoneNumber: formData.phoneNumber ? formData.phoneNumber : undefined,
      address: formData.address ? formData.address : undefined,
      city: formData.city ? formData.city : undefined,
      state: formData.state ? formData.state : undefined,
      postalCode: formData.postalCode ? formData.postalCode : undefined,
      country: formData.country ? formData.country : undefined,
      taxId: formData.taxId ? formData.taxId : undefined,
      creditLimit: parseFloat(formData.creditLimit) || 0,
      paymentTerms: formData.paymentTerms ? formData.paymentTerms : undefined,
      ...(editingId && { isActive: formData.isActive }),
    }

    const schema = editingId ? updateVendorSchema : createVendorSchema
    const result = schema.safeParse(submitData)

    if (!result.success) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      result.error.issues.forEach((err: any) => {
        if (err.path[0]) {
          errors[err.path[0].toString()] = err.message
        }
      })
      setFormErrors(errors)
      return false
    }

    return true
  }

  const handleSave = async () => {
    if (!validateForm()) {
      return
    }

    try {
      const baseData: CreateVendorInput = {
        vendorCode: formData.vendorCode,
        name: formData.name,
        contactPerson: formData.contactPerson ? formData.contactPerson : undefined,
        email: formData.email ? formData.email : undefined,
        phoneNumber: formData.phoneNumber ? formData.phoneNumber : undefined,
        address: formData.address ? formData.address : undefined,
        city: formData.city ? formData.city : undefined,
        state: formData.state ? formData.state : undefined,
        postalCode: formData.postalCode ? formData.postalCode : undefined,
        country: formData.country ? formData.country : undefined,
        taxId: formData.taxId ? formData.taxId : undefined,
        creditLimit: parseFloat(formData.creditLimit) || 0,
        paymentTerms: formData.paymentTerms ? formData.paymentTerms : undefined,
      }

      if (editingId) {
        const updateData: UpdateVendorInput = {
          ...baseData,
          isActive: formData.isActive,
        }
        await vendorService.updateVendor(editingId, updateData)
        push('success', 'Vendor updated successfully')
      } else {
        await vendorService.createVendor(baseData)
        push('success', 'Vendor created successfully')
      }

      setShowDialog(false)
      await loadVendors()
    } catch {
      push('error', editingId ? 'Failed to update vendor' : 'Failed to create vendor')
    }
  }

  const handleDialogClose = () => {
    setShowDialog(false)
    setFormErrors({})
  }

  return (
    <div className="space-y-4 p-4">
      <DashboardCard
        title="Vendor Management"
        subtitle="Create, update, and manage vendor master data for accounts payable"
      >
        <div className="space-y-4">
          <div className="flex items-center justify-between gap-4">
            <Input
              placeholder="Search by code or name..."
              value={searchText}
              onChange={(e: InputChangeEvent) => setSearchText((e.target.value as string) || '')}
              style={{ width: '300px' }}
            />
            <Button
              themeColor="primary"
              onClick={handleAddClick}
              disabled={!user || !['accountant', 'cfo', 'super-admin'].includes(user.role)}
            >
              + Add Vendor
            </Button>
          </div>

          {loading && <div style={{ marginBottom: '12px', color: 'var(--text-muted)' }}>Loading vendors...</div>}

          <DataTable data={filteredVendors} columns={vendorColumns} pageSizeOptions={[20, 50, 100]} />
        </div>
      </DashboardCard>

      {showDialog && (
        <Dialog title={editingId ? 'Edit Vendor' : 'Add Vendor'} onClose={handleDialogClose}>
          <div className="space-y-4 p-4" style={{ minWidth: '500px' }}>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium mb-1">Vendor Code*</label>
                <Input
                  name="vendorCode"
                  value={formData.vendorCode}
                  onChange={handleFormChange}
                  disabled={editingId !== null}
                  className={formErrors.vendorCode ? 'error' : ''}
                />
                {formErrors.vendorCode && <p className="text-red-500 text-xs">{formErrors.vendorCode}</p>}
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Vendor Name*</label>
                <Input
                  name="name"
                  value={formData.name}
                  onChange={handleFormChange}
                  className={formErrors.name ? 'error' : ''}
                />
                {formErrors.name && <p className="text-red-500 text-xs">{formErrors.name}</p>}
              </div>
            </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Contact Person</label>
              <Input name="contactPerson" value={formData.contactPerson} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Email</label>
              <Input name="email" value={formData.email} onChange={handleFormChange} type="email" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Phone</label>
              <Input name="phoneNumber" value={formData.phoneNumber} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Tax ID</label>
              <Input name="taxId" value={formData.taxId} onChange={handleFormChange} />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">Address</label>
            <Input name="address" value={formData.address} onChange={handleFormChange} />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">City</label>
              <Input name="city" value={formData.city} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">State</label>
              <Input name="state" value={formData.state} onChange={handleFormChange} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Postal Code</label>
              <Input name="postalCode" value={formData.postalCode} onChange={handleFormChange} />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Country</label>
              <Input name="country" value={formData.country} onChange={handleFormChange} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Credit Limit</label>
              <Input
                name="creditLimit"
                value={formData.creditLimit}
                onChange={handleFormChange}
                type="number"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Payment Terms</label>
              <Input name="paymentTerms" value={formData.paymentTerms} onChange={handleFormChange} />
            </div>
          </div>

            {editingId && (
              <label className="flex items-center gap-2">
                <input
                  type="checkbox"
                  name="isActive"
                  checked={formData.isActive}
                  onChange={handleFormChange}
                />
                <span className="text-sm font-medium">Active</span>
              </label>
            )}
          </div>

          <DialogActionsBar>
            <Button onClick={handleDialogClose}>Cancel</Button>
            <Button themeColor="primary" onClick={handleSave}>
              Save
            </Button>
          </DialogActionsBar>
        </Dialog>
      )}
    </div>
  )
}

import { expect, test } from '@playwright/test';
import { dismissToastIfPresent, gotoWithRetry, loginAsSuperAdmin, runId } from './helpers';

test.describe('Save and refresh persistence regressions', () => {
  test.beforeAll(async () => {
    test.skip(
      !process.env.E2E_SUPERADMIN_EMAIL || !process.env.E2E_SUPERADMIN_PASSWORD,
      'Skipping: E2E_SUPERADMIN_EMAIL or E2E_SUPERADMIN_PASSWORD not configured.',
    );
  });

  test.beforeEach(async ({ page }) => {
    await loginAsSuperAdmin(page);
  });

  test('user management: create employee persists after refresh', async ({ page }) => {
    const firstName = `E2E${runId.slice(0, 6)}`;
    const middleName = 'Persist';
    const lastName = `Create${runId.slice(-4)}`;
    const fullName = `${firstName} ${middleName} ${lastName}`;

    await gotoWithRetry(page, '/module/user-management');
    await page.waitForLoadState('networkidle');

    await page.getByRole('button', { name: 'Create Employee Account' }).click();
    await page.waitForSelector('[role="dialog"]', { state: 'visible' });

    // Kendo React <Input> is a controlled component: fill() sets the DOM value but does
    // NOT trigger Kendo's InputChangeEvent → React state stays empty.  pressSequentially()
    // fires real keyboard events that Kendo translates to InputChangeEvent → state updates.
    await page.locator('#create-first-name').pressSequentially(firstName);
    await page.locator('#create-middle-name').pressSequentially(middleName);
    await page.locator('#create-last-name').pressSequentially(lastName);

    // Native <input type="date"> — fill() works and fires the native onChange that
    // handleBirthdateChange listens to.  Fill this AFTER Kendo fields so the resulting
    // React re-render sees firstName/lastName already in state.
    await page.locator('#create-birthdate').fill('1997-03-14');
    // Age auto-computes from birthdate; do not fill separately to avoid conflicts.

    // Kendo TextArea for address
    await page.locator('#create-address').pressSequentially('123 E2E Street');

    // Kendo MaskedTextBox: type only the digit chars; mask inserts separators automatically
    await page.locator('#create-tin').pressSequentially('123456789000');
    await page.locator('#create-sss').pressSequentially('1234567890');

    // Department is now a select dropdown.
    await page.locator('#create-department').selectOption({ label: /finance/i });

    await page.getByRole('button', { name: 'Save Employee' }).click();
    // Dialog closes only when the save API call succeeds
    await page.waitForSelector('[role="dialog"]', { state: 'detached', timeout: 30000 });

    await page.reload({ waitUntil: 'networkidle' });
    await page.getByPlaceholder('Search by name or email').fill(firstName);
    await expect(page.getByRole('row', { name: new RegExp(fullName, 'i') })).toBeVisible({ timeout: 15000 });
  });

  test('user management: edit employee persists after refresh', async ({ page }) => {
    // Create a fresh employee in-test to avoid any dependency on demo/seed data.
    const firstName = `E2EEdit${runId.slice(0, 4)}`;
    const lastName = `Target${runId.slice(-4)}`;
    const originalDepartment = 'Finance';
    const newDepartment = `Finance-QA-${runId.slice(-4)}`;

    // Step 1: create the employee
    await gotoWithRetry(page, '/module/user-management');
    await page.waitForLoadState('networkidle');

    await page.getByRole('button', { name: 'Create Employee Account' }).click();
    await page.waitForSelector('[role="dialog"]', { state: 'visible' });

    await page.locator('#create-first-name').pressSequentially(firstName);
    await page.locator('#create-last-name').pressSequentially(lastName);
    await page.locator('#create-birthdate').fill('1990-06-15');
    await page.locator('#create-address').pressSequentially('456 Edit Ave');
    await page.locator('#create-tin').pressSequentially('111222333000');
    await page.locator('#create-sss').pressSequentially('1112223330');
    await page.locator('#create-department').selectOption({ label: /finance/i });

    await page.getByRole('button', { name: 'Save Employee' }).click();
    await page.waitForSelector('[role="dialog"]', { state: 'detached', timeout: 30000 });

    // Step 2: search for and edit that employee
    await page.reload({ waitUntil: 'networkidle' });
    await page.getByPlaceholder('Search by name or email').fill(firstName);

    const userRow = page.getByRole('row', { name: new RegExp(firstName, 'i') });
    await expect(userRow).toBeVisible({ timeout: 15000 });
    await userRow.getByRole('button', { name: 'Edit' }).click();
    await page.waitForSelector('[role="dialog"]', { state: 'visible' });

    await page.locator('#edit-department').click({ clickCount: 3 });
    await page.locator('#edit-department').pressSequentially(newDepartment);

    await page.getByRole('button', { name: 'Save Changes' }).click();
    await page.waitForSelector('[role="dialog"]', { state: 'detached', timeout: 30000 });

    // Step 3: reload and verify the department change persisted
    await page.reload({ waitUntil: 'networkidle' });
    await page.getByPlaceholder('Search by name or email').fill(firstName);
    await expect(
      page.getByRole('row', { name: new RegExp(firstName, 'i') }).getByRole('cell', { name: newDepartment }),
    ).toBeVisible({ timeout: 15000 });
  });

  // DEFECT: IntegrationSettingsModule.handleSaveSmtp() is a fake save — it does a
  // simulated 700 ms timeout and shows a success toast but makes NO API call and has
  // no backend endpoint. SMTP state lives only in React component state and resets to
  // INITIAL_SMTP (fromName: 'CMNetwork') on every page load.
  // Fix required: implement GET/PUT /api/admin/smtp-settings + wire the frontend.
  test.fixme('integration settings: smtp from name persists after refresh', async ({ page }) => {
    const value = `CMNetwork QA ${runId.slice(-6)}`;

    await gotoWithRetry(page, '/module/integration-settings');
    await page.getByLabel('From Name').fill(value);

    await page.getByRole('button', { name: 'Save' }).nth(1).click();
    await expect(page.getByText('SMTP settings saved.')).toBeVisible();

    await page.reload({ waitUntil: 'domcontentloaded' });
    await expect(page.getByLabel('From Name')).toHaveValue(value);
  });

  // DEFECT: RolesPermissionsModule.handleSavePerms() is a fake save — it does a
  // simulated 700 ms timeout and shows a success toast but makes NO API call.
  // The comment in the source reads: "Simulated API call — wire to backend when claims
  // endpoint is ready". Permissions live only in React state and reset on page reload.
  // Fix required: implement GET/PUT /api/admin/roles/{role}/permissions + wire the frontend.
  test.fixme('roles permissions: checkbox state persists after refresh', async ({ page }) => {
    await gotoWithRetry(page, '/module/roles-permissions');

    await page.getByRole('button', { name: 'Permissions' }).nth(1).click();
    const checkbox = page.locator('tr', { hasText: 'User Management' }).locator('input[type="checkbox"]').first();

    const original = await checkbox.isChecked();
    await checkbox.click();
    await page.getByRole('button', { name: 'Save Permissions' }).click();
    await expect(page.getByText(/permissions saved|saved/i)).toBeVisible();

    await page.reload({ waitUntil: 'domcontentloaded' });
    await page.getByRole('button', { name: 'Permissions' }).nth(1).click();
    const afterRefresh = await page.locator('tr', { hasText: 'User Management' }).locator('input[type="checkbox"]').first().isChecked();

    expect(afterRefresh).toBe(!original);

    // Restore the original state so this test can run repeatedly.
    if (afterRefresh !== original) {
      const restore = page.locator('tr', { hasText: 'User Management' }).locator('input[type="checkbox"]').first();
      await restore.click();
      await page.getByRole('button', { name: 'Save Permissions' }).click();
      await dismissToastIfPresent(page);
    }
  });

  test('security policy: toggle persists and can be restored', async ({ page }) => {
    await gotoWithRetry(page, '/module/security-policy');
    // Wait for the security policy API call to finish — the component sets dirty=false
    // once loadPolicy() resolves, so clicking the switch before that completes causes a
    // race condition where dirty gets reset to false and Save Policy stays disabled.
    await page.waitForLoadState('networkidle');

    const singleSessionSwitch = page.getByRole('switch', {
      name: 'Allow only one active session per user (force sign-out on new login)',
    });
    const originalChecked = (await singleSessionSwitch.getAttribute('aria-checked')) === 'true';

    await singleSessionSwitch.click();
    await page.getByRole('button', { name: 'Save Policy' }).click();
    await expect(page.getByText(/Security policy saved/i)).toBeVisible();

    await page.reload({ waitUntil: 'domcontentloaded' });
    const persisted =
      (await page
        .getByRole('switch', {
          name: 'Allow only one active session per user (force sign-out on new login)',
        })
        .getAttribute('aria-checked')) === 'true';

    expect(persisted).toBe(!originalChecked);

    const restoreSwitch = page.getByRole('switch', {
      name: 'Allow only one active session per user (force sign-out on new login)',
    });
    await restoreSwitch.click();

    // Cleanup should not fail the regression assertion if no pending changes exist.
    const savePolicyButton = page.getByRole('button', { name: 'Save Policy' });
    if (await savePolicyButton.isEnabled()) {
      await savePolicyButton.click();
      await expect(page.getByText(/Security policy saved/i)).toBeVisible();
    }
  });

  test('fiscal periods: close/open transition persists and can be restored', async ({ page }) => {
    await gotoWithRetry(page, '/module/fiscal-periods');

    const marchCard = page.locator('div', { hasText: 'March' }).first();
    const closeButton = marchCard.getByRole('button', { name: 'Close' }).first();
    const openButton = marchCard.getByRole('button', { name: 'Open' }).first();

    const wasOpen = await closeButton.isVisible().catch(() => false);

    if (wasOpen) {
      await closeButton.click();
      await expect(marchCard.getByRole('button', { name: 'Open' }).first()).toBeVisible();
    } else {
      await openButton.click();
      await expect(marchCard.getByRole('button', { name: 'Close' }).first()).toBeVisible();
    }

    await page.reload({ waitUntil: 'domcontentloaded' });

    const refreshedCard = page.locator('div', { hasText: 'March' }).first();
    if (wasOpen) {
      await expect(refreshedCard.getByRole('button', { name: 'Open' }).first()).toBeVisible();
      await refreshedCard.getByRole('button', { name: 'Open' }).first().click();
      await expect(refreshedCard.getByRole('button', { name: 'Close' }).first()).toBeVisible();
    } else {
      await expect(refreshedCard.getByRole('button', { name: 'Close' }).first()).toBeVisible();
      await refreshedCard.getByRole('button', { name: 'Close' }).first().click();
      await expect(refreshedCard.getByRole('button', { name: 'Open' }).first()).toBeVisible();
    }
  });
});
